const formatRelativeLocale = {
  lastWeek: "'ШҰвҖҚЫҶШӘЩғЫ•ЩҶ' eeee 'ШҜЫ•' p",
  yesterday: "'ШӘЫҲЩҶЫҲЪҜЫҲЩҶ ШҜЫ•' p",
  today: "'ШЁЫҲЪҜЫҲЩҶ ШҜЫ•' p",
  tomorrow: "'ШҰЫ•ШӘЫ• ШҜЫ•' p",
  nextWeek: "eeee 'ШҜЫ•' p",
  other: "P",
};

export const formatRelative = (token, _date, _baseDate, _options) =>
  formatRelativeLocale[token];
