    pm: /^а°…а°Әа°°а°ҫа°№аұҚа°Ёа°Ӯ/i,
    midnight: /^а°…а°°аұҚа°§/i,
    noon: /^а°®а°ҝа°ҹаұҚа°ҹ/i,
