const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "дёҚеҲ° 1 з§’",
    other: "дёҚеҲ° {{count}} з§’",
  },

  xSeconds: {
    one: "1 з§’",
    other: "{{count}} з§’",
  },

  halfAMinute: "еҚҠеҲҶй’ҹ",

  lessThanXMinutes: {
    one: "дёҚеҲ° 1 еҲҶй’ҹ",
    other: "дёҚеҲ° {{count}} еҲҶй’ҹ",
  },

  xMinutes: {
    one: "1 еҲҶй’ҹ",
    other: "{{count}} еҲҶй’ҹ",
  },

  xHours: {
    one: "1 е°Ҹж—¶",
    other: "{{count}} е°Ҹж—¶",
  },

  aboutXHours: {
    one: "еӨ§зәҰ 1 е°Ҹж—¶",
    other: "еӨ§зәҰ {{count}} е°Ҹж—¶",
  },

  xDays: {
    one: "1 еӨ©",
    other: "{{count}} еӨ©",
  },

  aboutXWeeks: {
    one: "еӨ§зәҰ 1 дёӘжҳҹжңҹ",
    other: "еӨ§зәҰ {{count}} дёӘжҳҹжңҹ",
  },

  xWeeks: {
    one: "1 дёӘжҳҹжңҹ",
    other: "{{count}} дёӘжҳҹжңҹ",
  },

  aboutXMonths: {
    one: "еӨ§зәҰ 1 дёӘжңҲ",
    other: "еӨ§зәҰ {{count}} дёӘжңҲ",
  },

  xMonths: {
    one: "1 дёӘжңҲ",
    other: "{{count}} дёӘжңҲ",
  },

  aboutXYears: {
    one: "еӨ§зәҰ 1 е№ҙ",
    other: "еӨ§зәҰ {{count}} е№ҙ",
  },

  xYears: {
    one: "1 е№ҙ",
    other: "{{count}} е№ҙ",
  },

  overXYears: {
    one: "и¶…иҝҮ 1 е№ҙ",
    other: "и¶…иҝҮ {{count}} е№ҙ",
  },

  almostXYears: {
    one: "е°Ҷиҝ‘ 1 е№ҙ",
    other: "е°Ҷиҝ‘ {{count}} е№ҙ",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + "еҶ…";
    } else {
      return result + "еүҚ";
    }
  }

  return result;
};
