import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?(ci|inci|nci|uncu|ГјncГј|ncДұ))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(b|a)$/i,
  abbreviated: /^(b\.?\s?c\.?|b\.?\s?c\.?\s?e\.?|a\.?\s?d\.?|c\.?\s?e\.?)$/i,
  wide: /^(bizim eradan ЙҷvvЙҷl|bizim era)$/i,
};
const parseEraPatterns = {
  any: [/^b$/i, /^(a|c)$/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]$/i,
  abbreviated: /^K[1234]$/i,
  wide: /^[1234](ci)? kvartal$/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[(?-i)yfmaisond]$/i,
  abbreviated: /^(Yan|Fev|Mar|Apr|May|Д°yun|Д°yul|Avq|Sen|Okt|Noy|Dek)$/i,
  wide: /^(Yanvar|Fevral|Mart|Aprel|May|Д°yun|Д°yul|Avgust|Sentyabr|Oktyabr|Noyabr|Dekabr)$/i,
};
const parseMonthPatterns = {
  narrow: [
    /^[(?-i)y]$/i,
    /^[(?-i)f]$/i,
    /^[(?-i)m]$/i,
    /^[(?-i)a]$/i,
    /^[(?-i)m]$/i,
    /^[(?-i)i]$/i,
    /^[(?-i)i]$/i,
    /^[(?-i)a]$/i,
    /^[(?-i)s]$/i,
    /^[(?-i)o]$/i,
    /^[(?-i)n]$/i,
    /^[(?-i)d]$/i,
  ],

  abbreviated: [
    /^Yan$/i,
    /^Fev$/i,
    /^Mar$/i,
    /^Apr$/i,
    /^May$/i,
    /^Д°yun$/i,
    /^Д°yul$/i,
    /^Avg$/i,
    /^Sen$/i,
    /^Okt$/i,
    /^Noy$/i,
    /^Dek$/i,
  ],

  wide: [
    /^Yanvar$/i,
    /^Fevral$/i,
    /^Mart$/i,
    /^Aprel$/i,
    /^May$/i,
    /^Д°yun$/i,
    /^Д°yul$/i,
    /^Avgust$/i,
    /^Sentyabr$/i,
    /^Oktyabr$/i,
    /^Noyabr$/i,
    /^Dekabr$/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(B\.|B\.e|ГҮ\.a|ГҮ\.|C\.a|C\.|Еһ\.)$/i,
  short: /^(B\.|B\.e|ГҮ\.a|ГҮ\.|C\.a|C\.|Еһ\.)$/i,
  abbreviated: /^(Baz\.e|ГҮЙҷr|ГҮЙҷr\.a|CГјm|CГјm\.a|ЕһЙҷ)$/i,
  wide: /^(Bazar|Bazar ertЙҷsi|ГҮЙҷrЕҹЙҷnbЙҷ axЕҹamДұ|ГҮЙҷrЕҹЙҷnbЙҷ|CГјmЙҷ axЕҹamДұ|CГјmЙҷ|ЕһЙҷnbЙҷ)$/i,
};
const parseDayPatterns = {
  narrow: [
    /^B\.$/i,
    /^B\.e$/i,
    /^ГҮ\.a$/i,
    /^ГҮ\.$/i,
    /^C\.a$/i,
    /^C\.$/i,
    /^Еһ\.$/i,
  ],

  abbreviated: [
    /^Baz$/i,
    /^Baz\.e$/i,
    /^ГҮЙҷr\.a$/i,
    /^ГҮЙҷr$/i,
    /^CГјm\.a$/i,
    /^CГјm$/i,
    /^ЕһЙҷ$/i,
  ],

  wide: [
    /^Bazar$/i,
    /^Bazar ertЙҷsi$/i,
    /^ГҮЙҷrЕҹЙҷnbЙҷ axЕҹamДұ$/i,
    /^ГҮЙҷrЕҹЙҷnbЙҷ$/i,
    /^CГјmЙҷ axЕҹamДұ$/i,
    /^CГјmЙҷ$/i,
    /^ЕһЙҷnbЙҷ$/i,
  ],

  any: [
    /^B\.$/i,
    /^B\.e$/i,
    /^ГҮ\.a$/i,
    /^ГҮ\.$/i,
    /^C\.a$/i,
    /^C\.$/i,
    /^Еһ\.$/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow: /^(a|p|gecЙҷyarДұ|gГјn|sЙҷhЙҷr|gГјndГјz|axЕҹam|gecЙҷ)$/i,
  any: /^(am|pm|a\.m\.|p\.m\.|AM|PM|gecЙҷyarДұ|gГјn|sЙҷhЙҷr|gГјndГјz|axЕҹam|gecЙҷ)$/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^a$/i,
    pm: /^p$/i,
    midnight: /^gecЙҷyarДұ$/i,
    noon: /^gГјn$/i,
    morning: /sЙҷhЙҷr$/i,
    afternoon: /gГјndГјz$/i,
    evening: /axЕҹam$/i,
    night: /gecЙҷ$/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "narrow",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
