import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?(Рө|СҸ|Р№|РҫРө|СҢРө|Р°СҸ|СҢСҸ|СӢР№|РҫР№|РёР№|СӢР№))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((РҙРҫ )?РҪ\.?\s?СҚ\.?)/i,
  abbreviated: /^((РҙРҫ )?РҪ\.?\s?СҚ\.?)/i,
  wide: /^(РҙРҫ РҪР°СҲРөР№ СҚСҖСӢ|РҪР°СҲРөР№ СҚСҖСӢ|РҪР°СҲР° СҚСҖР°)/i,
};
const parseEraPatterns = {
  any: [/^Рҙ/i, /^РҪ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[СӢРҫРё]?Р№?)? РәРІ.?/i,
  wide: /^[1234](-?[СӢРҫРё]?Р№?)? РәРІР°СҖСӮР°Р»/i,
};

const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[СҸС„РјР°РёСҒРҫРҪРҙ]/i,
  abbreviated:
    /^(СҸРҪРІ|С„РөРІ|РјР°СҖСӮ?|Р°РҝСҖ|РјР°[Р№СҸ]|РёСҺРҪ[СҢСҸ]?|РёСҺР»[СҢСҸ]?|Р°РІРі|СҒРөРҪСӮ?|РҫРәСӮ|РҪРҫСҸРұ?|РҙРөРә)\.?/i,
  wide: /^(СҸРҪРІР°СҖ[СҢСҸ]|С„РөРІСҖР°Р»[СҢСҸ]|РјР°СҖСӮР°?|Р°РҝСҖРөР»[СҢСҸ]|РјР°[Р№СҸ]|РёСҺРҪ[СҢСҸ]|РёСҺР»[СҢСҸ]|Р°РІРіСғСҒСӮР°?|СҒРөРҪСӮСҸРұСҖ[СҢСҸ]|РҫРәСӮСҸРұСҖ[СҢСҸ]|РҫРәСӮСҸРұСҖ[СҢСҸ]|РҪРҫСҸРұСҖ[СҢСҸ]|РҙРөРәР°РұСҖ[СҢСҸ])/i,
};

const parseMonthPatterns = {
  narrow: [
    /^СҸ/i,
    /^С„/i,
    /^Рј/i,
    /^Р°/i,
    /^Рј/i,
    /^Рё/i,
    /^Рё/i,
    /^Р°/i,
    /^СҒ/i,
    /^Рҫ/i,
    /^РҪ/i,
    /^СҸ/i,
  ],

  any: [
    /^СҸ/i,
    /^С„/i,
    /^РјР°СҖ/i,
    /^Р°Рҝ/i,
    /^РјР°[Р№СҸ]/i,
    /^РёСҺРҪ/i,
    /^РёСҺР»/i,
    /^Р°РІ/i,
    /^СҒ/i,
    /^Рҫ/i,
    /^РҪ/i,
    /^Рҙ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[РІРҝСҒСҮ]/i,
  short: /^(РІСҒ|РІРҫ|РҝРҪ|РҝРҫ|РІСӮ|СҒСҖ|СҮСӮ|СҮРө|РҝСӮ|РҝСҸ|СҒРұ|СҒСғ)\.?/i,
  abbreviated: /^(РІСҒРә|РІРҫСҒ|РҝРҪРҙ|РҝРҫРҪ|РІСӮСҖ|РІСӮРҫ|СҒСҖРҙ|СҒСҖРө|СҮСӮРІ|СҮРөСӮ|РҝСӮРҪ|РҝСҸСӮ|СҒСғРұ).?/i,
  wide: /^(РІРҫСҒРәСҖРөСҒРөРҪСҢ[РөСҸ]|РҝРҫРҪРөРҙРөР»СҢРҪРёРәР°?|РІСӮРҫСҖРҪРёРәР°?|СҒСҖРөРҙ[Р°СӢ]|СҮРөСӮРІРөСҖРіР°?|РҝСҸСӮРҪРёСҶ[Р°СӢ]|СҒСғРұРұРҫСӮ[Р°СӢ])/i,
};

const parseDayPatterns = {
  narrow: [/^РІ/i, /^Рҝ/i, /^РІ/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^СҒ/i],
  any: [/^РІ[РҫСҒ]/i, /^Рҝ[РҫРҪ]/i, /^РІ/i, /^СҒСҖ/i, /^СҮ/i, /^Рҝ[СҸСӮ]/i, /^СҒ[СғРұ]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([РҙРҝ]Рҝ|РҝРҫР»РҪ\.?|РҝРҫР»Рҙ\.?|СғСӮСҖ[РҫР°]|РҙРөРҪСҢ|РҙРҪСҸ|РІРөСҮ\.?|РҪРҫСҮ[СҢРё])/i,
  abbreviated: /^([РҙРҝ]Рҝ|РҝРҫР»РҪ\.?|РҝРҫР»Рҙ\.?|СғСӮСҖ[РҫР°]|РҙРөРҪСҢ|РҙРҪСҸ|РІРөСҮ\.?|РҪРҫСҮ[СҢРё])/i,
  wide: /^([РҙРҝ]Рҝ|РҝРҫР»РҪРҫСҮСҢ|РҝРҫР»РҙРөРҪСҢ|СғСӮСҖ[РҫР°]|РҙРөРҪСҢ|РҙРҪСҸ|РІРөСҮРөСҖР°?|РҪРҫСҮ[СҢРё])/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^РҙРҝ/i,
    pm: /^РҝРҝ/i,
    midnight: /^РҝРҫР»РҪ/i,
    noon: /^РҝРҫР»Рҙ/i,
    morning: /^Сғ/i,
    afternoon: /^Рҙ[РөРҪ]/i,
    evening: /^РІ/i,
    night: /^РҪ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
