function dateOrdinalNumber(number, localeNumber) {
  if (number > 18 && number <= 31) {
    return localeNumber + "аҰ¶а§Ү";
  } else {
    switch (number) {
      case 1:
        return localeNumber + "аҰІаҰҫ";
      case 2:
      case 3:
        return localeNumber + "аҰ°аҰҫ";
      case 4:
        return localeNumber + "аҰ аҰҫ";
      default:
        return localeNumber + "аҰҮ";
    }
  }
}

const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const localeNumber = numberToLocale(number);
  const unit = options?.unit;

  if (unit === "date") {
    return dateOrdinalNumber(number, localeNumber);
  }
  if (number > 10 || number === 0) return localeNumber + "аҰӨаҰ®";

  const rem10 = number % 10;
  switch (rem10) {
    case 2:
    case 3:
      return localeNumber + "а§ҹ";
    case 4:
      return localeNumber + "аҰ°а§ҚаҰҘ";
    case 6:
      return localeNumber + "аҰ·а§ҚаҰ ";
    default:
      return localeNumber + "аҰ®";
  }
};

