import { isSameWeek } from "../../../isSameWeek.js";

const weekdays = [
  "svД“tdienДҒ",
  "pirmdienДҒ",
  "otrdienДҒ",
  "treЕЎdienДҒ",
  "ceturtdienДҒ",
  "piektdienДҒ",
  "sestdienДҒ",
];

const formatRelativeLocale = {
  lastWeek: (date, baseDate, options) => {
    if (isSameWeek(date, baseDate, options)) {
      return "eeee 'plkst.' p";
    }

    const weekday = weekdays[date.getDay()];
    return "'PagДҒjuЕЎДҒ " + weekday + " plkst.' p";
  },
  yesterday: "'Vakar plkst.' p",
  today: "'Е odien plkst.' p",
  tomorrow: "'RД«t plkst.' p",
  nextWeek: (date, baseDate, options) => {
    if (isSameWeek(date, baseDate, options)) {
      return "eeee 'plkst.' p";
    }

    const weekday = weekdays[date.getDay()];
    return "'NДҒkamajДҒ " + weekday + " plkst.' p";
  },
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
