import { isSameWeek } from "../../../isSameWeek.js";

const weekdays = [
  "РҪРөРҙРөР»Р°",
  "РҝРҫРҪРөРҙРөР»РҪРёРә",
  "РІСӮРҫСҖРҪРёРә",
  "СҒСҖРөРҙР°",
  "СҮРөСӮРІСҖСӮРҫРә",
  "РҝРөСӮРҫРә",
  "СҒР°РұРҫСӮР°",
];

function lastWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'РјРёРҪР°СӮР°СӮР° " + weekday + " РІРҫ' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'РјРёРҪР°СӮРёРҫСӮ " + weekday + " РІРҫ' p";
  }
}

function thisWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'РҫРІР° " + weekday + " РІo' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'РҫРІРҫСҳ " + weekday + " РІo' p";
  }
}

function nextWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'СҒР»РөРҙРҪР°СӮР° " + weekday + " РІo' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'СҒР»РөРҙРҪРёРҫСӮ " + weekday + " РІo' p";
  }
}

const formatRelativeLocale = {
  lastWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return lastWeek(day);
    }
  },
  yesterday: "'РІСҮРөСҖР° РІРҫ' p",
  today: "'РҙРөРҪРөСҒ РІРҫ' p",
  tomorrow: "'СғСӮСҖРө РІРҫ' p",
  nextWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return nextWeek(day);
    }
  },
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
