const formatDistanceLocale = {
  lessThanXSeconds: "бһҸбһ·бһ…бһҮбһ¶бһ„ {{count}} бһңбһ·бһ“бһ¶бһ‘бһё",
  xSeconds: "{{count}} бһңбһ·бһ“бһ¶бһ‘бһё",
  halfAMinute: "бһҖбһ“бҹ’бһӣбҹҮбһ“бһ¶бһ‘бһё",
  lessThanXMinutes: "бһҸбһ·бһ…бһҮбһ¶бһ„ {{count}} бһ“бһ¶бһ‘бһё",
  xMinutes: "{{count}} бһ“бһ¶бһ‘бһё",
  aboutXHours: "бһ”бҹ’бһҡбһ бҹӮбһӣ {{count}} бһҳбҹүбҹ„бһ„",
  xHours: "{{count}} бһҳбҹүбҹ„бһ„",
  xDays: "{{count}} бһҗбҹ’бһ„бҹғ",
  aboutXWeeks: "бһ”бҹ’бһҡбһ бҹӮбһӣ {{count}} бһҹбһ”бҹ’бһҸбһ¶бһ бҹҚ",
  xWeeks: "{{count}} бһҹбһ”бҹ’бһҸбһ¶бһ бҹҚ",
  aboutXMonths: "бһ”бҹ’бһҡбһ бҹӮбһӣ {{count}} бһҒбҹӮ",
  xMonths: "{{count}} бһҒбҹӮ",
  aboutXYears: "бһ”бҹ’бһҡбһ бҹӮбһӣ {{count}} бһҶбҹ’бһ“бһ¶бҹҶ",
  xYears: "{{count}} бһҶбҹ’бһ“бһ¶бҹҶ",
  overXYears: "бһҮбһ¶бһ„ {{count}} бһҶбҹ’бһ“бһ¶бҹҶ",
  almostXYears: "бһҮбһ·бһҸ {{count}} бһҶбҹ’бһ“бһ¶бҹҶ",
};

export const formatDistance = (token, count, options) => {
  const tokenValue = formatDistanceLocale[token];

  let result = tokenValue;

  if (typeof count === "number") {
    result = result.replace("{{count}}", count.toString());
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "бһҖбҹ’бһ“бһ»бһ„бһҡбһҷбҹҲбһ–бҹҒбһӣ " + result;
    } else {
      return result + "бһҳбһ»бһ“";
    }
  }

  return result;
};
