import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?[РІСҖРјСӮ][Рё])?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((РҝСҖ)?РҪ\.?\s?Рө\.?)/i,
  abbreviated: /^((РҝСҖ)?РҪ\.?\s?Рө\.?)/i,
  wide: /^(РҝСҖРөРҙ РҪР°СҲР°СӮР° РөСҖР°|РҪР°СҲР°СӮР° РөСҖР°)/i,
};
const parseEraPatterns = {
  any: [/^Рҝ/i, /^РҪ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[РІСҖСӮ]?Рё?)? РәРІ.?/i,
  wide: /^[1234](-?[РІСҖСӮ]?Рё?)? РәРІР°СҖСӮР°Р»/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchDayPatterns = {
  narrow: /^[РҪРҝРІСҒСҮ]/i,
  short: /^(РҪРө|РҝРҫ|РІСӮ|СҒСҖ|СҮРө|РҝРө|СҒР°)/i,
  abbreviated: /^(РҪРөРҙ|РҝРҫРҪ|РІСӮРҫ|СҒСҖРө|СҮРөСӮ|РҝРөСӮ|СҒР°Рұ)/i,
  wide: /^(РҪРөРҙРөР»Р°|РҝРҫРҪРөРҙРөР»РҪРёРә|РІСӮРҫСҖРҪРёРә|СҒСҖРөРҙР°|СҮРөСӮРІСҖСӮРҫРә|РҝРөСӮРҫРә|СҒР°РұРҫСӮР°)/i,
};

const parseDayPatterns = {
  narrow: [/^РҪ/i, /^Рҝ/i, /^РІ/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^СҒ/i],
  any: [/^РҪ[РөРҙ]/i, /^Рҝ[РҫРҪ]/i, /^РІСӮ/i, /^СҒСҖ/i, /^СҮ[РөСӮ]/i, /^Рҝ[РөСӮ]/i, /^СҒ[Р°Рұ]/i],
};

const matchMonthPatterns = {
  abbreviated: /^(СҳР°РҪ|С„РөРІ|РјР°СҖ|Р°РҝСҖ|РјР°Сҳ|СҳСғРҪ|СҳСғР»|Р°РІРі|СҒРөРҝ|РҫРәСӮ|РҪРҫРөРј|РҙРөРә)/i,
  wide: /^(СҳР°РҪСғР°СҖРё|С„РөРІСҖСғР°СҖРё|РјР°СҖСӮ|Р°РҝСҖРёР»|РјР°Сҳ|СҳСғРҪРё|СҳСғР»Рё|Р°РІРіСғСҒСӮ|СҒРөРҝСӮРөРјРІСҖРё|РҫРәСӮРҫРјРІСҖРё|РҪРҫРөРјРІСҖРё|РҙРөРәРөРјРІСҖРё)/i,
};
const parseMonthPatterns = {
  any: [
    /^СҳР°/i,
    /^РӨ/i,
    /^РјР°СҖ/i,
    /^Р°Рҝ/i,
    /^РјР°Сҳ/i,
    /^СҳСғРҪ/i,
    /^СҳСғР»/i,
    /^Р°РІ/i,
    /^СҒРө/i,
    /^РҫРәСӮ/i,
    /^РҪРҫ/i,
    /^РҙРө/i,
  ],
};

const matchDayPeriodPatterns = {
  any: /^(РҝСҖРөСӮРҝ|РҝРҫРҝР»|РҝРҫР»РҪРҫСң|СғСӮСҖРҫ|РҝР»Р°РҙРҪРө|РІРөСҮРөСҖ|РҪРҫСң)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /РҝСҖРөСӮРҝР»Р°РҙРҪРө/i,
    pm: /РҝРҫРҝР»Р°РҙРҪРө/i,
    midnight: /РҝРҫР»РҪРҫСң/i,
    noon: /РҪР°РҝР»Р°РҙРҪРө/i,
    morning: /РҪР°СғСӮСҖРҫ/i,
    afternoon: /РҝРҫРҝР»Р°РҙРҪРө/i,
    evening: /РҪР°РІРөСҮРөСҖ/i,
    night: /РҪРҫСңРө/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
