import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)\./i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(РҝСҖ\.РҪ\.Рө\.|РҗР”)/i,
  abbreviated: /^(РҝСҖ\.\s?РҘСҖ\.|РҝРҫ\.\s?РҘСҖ\.)/i,
  wide: /^(РҹСҖРө РҘСҖРёСҒСӮР°|РҝСҖРө РҪРҫРІРө РөСҖРө|РҹРҫСҒР»Рө РҘСҖРёСҒСӮР°|РҪРҫРІР° РөСҖР°)/i,
};
const parseEraPatterns = {
  any: [/^РҝСҖ/i, /^(РҝРҫ|РҪРҫРІР°)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]\.\s?РәРІ\.?/i,
  wide: /^[1234]\. РәРІР°СҖСӮР°Р»/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(10|11|12|[123456789])\./i,
  abbreviated: /^(СҳР°РҪ|С„РөРұ|РјР°СҖ|Р°РҝСҖ|РјР°Сҳ|СҳСғРҪ|СҳСғР»|Р°РІРі|СҒРөРҝ|РҫРәСӮ|РҪРҫРІ|РҙРөСҶ)/i,
  wide: /^((СҳР°РҪСғР°СҖ|СҳР°РҪСғР°СҖР°)|(С„РөРұСҖСғР°СҖ|С„РөРұСҖСғР°СҖР°)|(РјР°СҖСӮ|РјР°СҖСӮР°)|(Р°РҝСҖРёР»|Р°РҝСҖРёР»Р°)|(РјСҳР°|РјР°СҳР°)|(СҳСғРҪ|СҳСғРҪР°)|(СҳСғР»|СҳСғР»Р°)|(Р°РІРіСғСҒСӮ|Р°РІРіСғСҒСӮР°)|(СҒРөРҝСӮРөРјРұР°СҖ|СҒРөРҝСӮРөРјРұСҖР°)|(РҫРәСӮРҫРұР°СҖ|РҫРәСӮРҫРұСҖР°)|(РҪРҫРІРөРјРұР°СҖ|РҪРҫРІРөРјРұСҖР°)|(РҙРөСҶРөРјРұР°СҖ|РҙРөСҶРөРјРұСҖР°))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^1/i,
    /^2/i,
    /^3/i,
    /^4/i,
    /^5/i,
    /^6/i,
    /^7/i,
    /^8/i,
    /^9/i,
    /^10/i,
    /^11/i,
    /^12/i,
  ],

  any: [
    /^СҳР°/i,
    /^С„/i,
    /^РјР°СҖ/i,
    /^Р°Рҝ/i,
    /^РјР°Сҳ/i,
    /^СҳСғРҪ/i,
    /^СҳСғР»/i,
    /^Р°РІРі/i,
    /^СҒ/i,
    /^Рҫ/i,
    /^РҪ/i,
    /^Рҙ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[РҝСғСҒСҮРҪ]/i,
  short: /^(РҪРөРҙ|РҝРҫРҪ|СғСӮРҫ|СҒСҖРө|СҮРөСӮ|РҝРөСӮ|СҒСғРұ)/i,
  abbreviated: /^(РҪРөРҙ|РҝРҫРҪ|СғСӮРҫ|СҒСҖРө|СҮРөСӮ|РҝРөСӮ|СҒСғРұ)/i,
  wide: /^(РҪРөРҙРөСҷР°|РҝРҫРҪРөРҙРөСҷР°Рә|СғСӮРҫСҖР°Рә|СҒСҖРөРҙР°|СҮРөСӮРІСҖСӮР°Рә|РҝРөСӮР°Рә|СҒСғРұРҫСӮР°)/i,
};
const parseDayPatterns = {
  narrow: [/^Рҝ/i, /^Сғ/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^СҒ/i, /^РҪ/i],
  any: [/^РҪРөРҙ/i, /^РҝРҫРҪ/i, /^СғСӮРҫ/i, /^СҒСҖРө/i, /^СҮРөСӮ/i, /^РҝРөСӮ/i, /^СҒСғРұ/i],
};

const matchDayPeriodPatterns = {
  any: /^(Р°Рј|РҝРј|РҝРҫРҪРҫСӣ|(РҝРҫ)?РҝРҫРҙРҪРө|СғРІРөСҮРө|РҪРҫСӣСғ|РҝРҫСҒР»Рө РҝРҫРҙРҪРө|СғСҳСғСӮСҖСғ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^a/i,
    pm: /^p/i,
    midnight: /^РҝРҫРҪРҫ/i,
    noon: /^РҝРҫРҙ/i,
    morning: /СғСҳСғСӮСҖСғ/i,
    afternoon: /(РҝРҫСҒР»Рө\s|РҝРҫ)+РҝРҫРҙРҪРө/i,
    evening: /(СғРІРөСҮРө)/i,
    night: /(РҪРҫСӣСғ)/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
