import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";
import { buildMatchFn } from "../../_lib/buildMatchFn.js";

const matchOrdinalNumberPattern = /^(\d+)(th|st|nd|rd)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /[ЩӮШЁ]/,
  abbreviated: /[ЩӮШЁ]\.Щ…\./,
  wide: /(ЩӮШЁЩ„|ШЁШ№ШҜ) Ш§Щ„Щ…ЩҠЩ„Ш§ШҜ/,
};
const parseEraPatterns = {
  any: [/ЩӮШЁЩ„/, /ШЁШ№ШҜ/],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /Шұ[1234]/,
  wide: /Ш§Щ„ШұШЁШ№ (Ш§Щ„ШЈЩҲЩ„|Ш§Щ„Ш«Ш§ЩҶЩҠ|Ш§Щ„Ш«Ш§Щ„Ш«|Ш§Щ„ШұШ§ШЁШ№)/,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[Ш¬ЩҒЩ…ШЈШіЩҶШҜ]/,
  abbreviated:
    /^(Ш¬Ш§ЩҶЩҒЩҠ|ЩҒЩҠЩҒШұЩҠ|Щ…Ш§ШұШі|ШЈЩҒШұЩҠЩ„|Щ…Ш§ЩҠ|Ш¬ЩҲШ§ЩҶ|Ш¬ЩҲЩҠЩ„ЩҠШ©|ШЈЩҲШӘ|ШіШЁШӘЩ…ШЁШұ|ШЈЩғШӘЩҲШЁШұ|ЩҶЩҲЩҒЩ…ШЁШұ|ШҜЩҠШіЩ…ШЁШұ)/,
  wide: /^(Ш¬Ш§ЩҶЩҒЩҠ|ЩҒЩҠЩҒШұЩҠ|Щ…Ш§ШұШі|ШЈЩҒШұЩҠЩ„|Щ…Ш§ЩҠ|Ш¬ЩҲШ§ЩҶ|Ш¬ЩҲЩҠЩ„ЩҠШ©|ШЈЩҲШӘ|ШіШЁШӘЩ…ШЁШұ|ШЈЩғШӘЩҲШЁШұ|ЩҶЩҲЩҒЩ…ШЁШұ|ШҜЩҠШіЩ…ШЁШұ)/,
};
const parseMonthPatterns = {
  narrow: [
    /^Ш¬/i,
    /^ЩҒ/i,
    /^Щ…/i,
    /^ШЈ/i,
    /^Щ…/i,
    /^Ш¬/i,
    /^Ш¬/i,
    /^ШЈ/i,
    /^Ші/i,
    /^ШЈ/i,
    /^ЩҶ/i,
    /^ШҜ/i,
  ],

  any: [
    /^Ш¬Ш§ЩҶЩҒЩҠ/i,
    /^ЩҒЩҠЩҒШұЩҠ/i,
    /^Щ…Ш§ШұШі/i,
    /^ШЈЩҒШұЩҠЩ„/i,
    /^Щ…Ш§ЩҠ/i,
    /^Ш¬ЩҲШ§ЩҶ/i,
    /^Ш¬ЩҲЩҠЩ„ЩҠШ©/i,
    /^ШЈЩҲШӘ/i,
    /^ШіШЁШӘЩ…ШЁШұ/i,
    /^ШЈЩғШӘЩҲШЁШұ/i,
    /^ЩҶЩҲЩҒЩ…ШЁШұ/i,
    /^ШҜЩҠШіЩ…ШЁШұ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ШӯЩҶШ«ШұШ®Ш¬Ші]/i,
  short: /^(ШЈШӯШҜ|Ш§Ш«ЩҶЩҠЩҶ|Ш«Щ„Ш§Ш«Ш§ШЎ|ШЈШұШЁШ№Ш§ШЎ|Ш®Щ…ЩҠШі|Ш¬Щ…Ш№Ш©|ШіШЁШӘ)/i,
  abbreviated: /^(ШЈШӯШҜ|Ш§Ш«ЩҶЩҠЩҶ|Ш«Щ„Ш§Ш«Ш§ШЎ|ШЈШұШЁШ№Ш§ШЎ|Ш®Щ…ЩҠШі|Ш¬Щ…Ш№Ш©|ШіШЁШӘ)/i,
  wide: /^(Ш§Щ„ШЈШӯШҜ|Ш§Щ„Ш§Ш«ЩҶЩҠЩҶ|Ш§Щ„Ш«Щ„Ш§Ш«Ш§ШЎ|Ш§Щ„ШЈШұШЁШ№Ш§ШЎ|Ш§Щ„Ш®Щ…ЩҠШі|Ш§Щ„Ш¬Щ…Ш№Ш©|Ш§Щ„ШіШЁШӘ)/i,
};
const parseDayPatterns = {
  narrow: [/^Шӯ/i, /^ЩҶ/i, /^Ш«/i, /^Шұ/i, /^Ш®/i, /^Ш¬/i, /^Ші/i],
  wide: [
    /^Ш§Щ„ШЈШӯШҜ/i,
    /^Ш§Щ„Ш§Ш«ЩҶЩҠЩҶ/i,
    /^Ш§Щ„Ш«Щ„Ш§Ш«Ш§ШЎ/i,
    /^Ш§Щ„ШЈШұШЁШ№Ш§ШЎ/i,
    /^Ш§Щ„Ш®Щ…ЩҠШі/i,
    /^Ш§Щ„Ш¬Щ…Ш№Ш©/i,
    /^Ш§Щ„ШіШЁШӘ/i,
  ],

  any: [/^ШЈШӯ/i, /^Ш§Ш«/i, /^Ш«/i, /^ШЈШұ/i, /^Ш®/i, /^Ш¬/i, /^Ші/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(Шө|Ш№|ЩҶ Щ„|Щ„|(ЩҒЩҠ|Щ…Ш№) (ШөШЁШ§Шӯ|ЩӮШ§ЩҠЩ„Ш©|Ш№ШҙЩҠШ©|Щ„ЩҠЩ„))/,
  any: /^([ШөШ№]|ЩҶШө Ш§Щ„Щ„ЩҠЩ„|ЩӮШ§ЩҠЩ„Ш©|(ЩҒЩҠ|Щ…Ш№) (ШөШЁШ§Шӯ|ЩӮШ§ЩҠЩ„Ш©|Ш№ШҙЩҠШ©|Щ„ЩҠЩ„))/,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^Шө/,
    pm: /^Ш№/,
    midnight: /ЩҶШө Ш§Щ„Щ„ЩҠЩ„/,
    noon: /ЩӮШ§ЩҠЩ„Ш©/,
    afternoon: /ШЁШ№ШҜ Ш§Щ„ЩӮШ§ЩҠЩ„Ш©/,
    morning: /ШөШЁШ§Шӯ/,
    evening: /Ш№ШҙЩҠШ©/,
    night: /Щ„ЩҠЩ„/,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
