import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(th|st|nd|rd)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(Щҫ|ШҜ)/i,
  abbreviated: /^(Щҫ-ШІ|ШҜ.ШІ)/i,
  wide: /^(ЩҫЫҺШҙ ШІШ§ЫҢЩҶ| ШҜЩҲШ§ЫҢ ШІШ§ЫҢЩҶ)/i,
};
const parseEraPatterns = {
  any: [/^ШҜ/g, /^Щҫ/g],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^Щ…[1234]ЪҶ/i,
  wide: /^(ЫҢЫ•Ъ©Ы•Щ…|ШҜЩҲЩҲЫ•Щ…|ШіЫҺЫҢЫ•Щ…| ЪҶЩҲШ§ШұЫ•Щ…) (ЪҶШ§ШұЫ•ЪҜЫҢ)? quarter/i,
};
const parseQuarterPatterns = {
  wide: [/ЪҶШ§ШұЫ•ЪҜЫҢ ЫҢЫ•Ъ©Ы•Щ…/, /ЪҶШ§ШұЫ•ЪҜЫҢ ШҜЩҲЩҲЫ•Щ…/, /ЪҶШ§ШұЫ•ЪҜЫҢ ШіЩҠЫҢЫ•Щ…/, /ЪҶШ§ШұЫ•ЪҜЫҢ ЪҶЩҲШ§ШұЫ•Щ…/],

  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(Ъ©-ШҜ|Шҙ|ШҰШ§|ЩҶ|Щ…|Шӯ|ШӘ|ШҰЫ•|ШӘШҙ-ЫҢ|ШӘШҙ-ШҜ|Ъ©-ЫҢ)/i,
  abbreviated:
    /^(Ъ©Ш§ЩҶ-ШҜЩҲЩҲ|ШҙЩҲШЁ|ШҰШ§ШҜ|ЩҶЫҢШі|Щ…Ш§ЫҢШі|ШӯЩҲШІ|ШӘЫ•Щ…|ШҰШ§ШЁ|ШҰЫ•Щ„|ШӘШҙ-ЫҢЫ•Ъ©|ШӘШҙ-ШҜЩҲЩҲ|Ъ©Ш§ЩҶ-ЫҢЫ•Ъ©)/i,
  wide: /^(Ъ©Ш§ЩҶЩҲЩҲЩҶЫҢ ШҜЩҲЩҲЫ•Щ…|ШҙЩҲШЁШ§ШӘ|ШҰШ§ШҜШ§Шұ|ЩҶЫҢШіШ§ЩҶ|Щ…Ш§ЫҢШі|ШӯЩҲШІЫ•ЫҢШұШ§ЩҶ|ШӘЫ•Щ…Щ…ЩҲШІ|ШҰШ§ШЁ|ШҰЫ•ЫҢЩ„ЩҲЩ„|ШӘШҙШұЫҢЩҶЫҢ ЫҢЫ•Ъ©Ы•Щ…|ШӘШҙШұЫҢЩҶЫҢ ШҜЩҲЩҲЫ•Щ…|Ъ©Ш§ЩҶЩҲЩҲЩҶЫҢ ЫҢЫ•Ъ©Ы•Щ…)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^Ъ©-ШҜ/i,
    /^Шҙ/i,
    /^ШҰШ§/i,
    /^ЩҶ/i,
    /^Щ…/i,
    /^Шӯ/i,
    /^ШӘ/i,
    /^ШҰШ§/i,
    /^ШҰЫ•/i,
    /^ШӘШҙ-ЫҢ/i,
    /^ШӘШҙ-ШҜ/i,
    /^Ъ©-ЫҢ/i,
  ],

  any: [
    /^Ъ©Ш§ЩҶ-ШҜЩҲЩҲ/i,
    /^ШҙЩҲШЁ/i,
    /^ШҰШ§ШҜ/i,
    /^ЩҶЫҢШі/i,
    /^Щ…Ш§ЫҢШі/i,
    /^ШӯЩҲШІ/i,
    /^ШӘЫ•Щ…/i,
    /^ШҰШ§ШЁ/i,
    /^ШҰЫ•Щ„/i,
    /^ШӘШҙ-ЫҢЫ•Ъ©/i,
    /^ШӘШҙ-ШҜЩҲЩҲ/i,
    /^|Ъ©Ш§ЩҶ-ЫҢЫ•Ъ©/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(Шҙ|ЫҢ|ШҜ|Ші|ЪҶ|Щҫ|ЩҮЫ•)/i,
  short: /^(ЫҢЫ•-ШҙЫ•|ШҜЩҲЩҲ-ШҙЫ•|ШіЫҺ-ШҙЫ•|ЪҶЩҲ-ШҙЫ•|ЩҫЫҺ-ШҙЫ•|ЩҮЫ•|ШҙЫ•)/i,
  abbreviated: /^(ЫҢЫ•Ъ©-ШҙЫ•Щ…|ШҜЩҲЩҲ-ШҙЫ•Щ…|ШіЫҺ-ШҙЫ•Щ…|ЪҶЩҲШ§Шұ-ШҙЫ•Щ…|ЩҫЫҺЩҶШ®-ШҙЫ•Щ…|ЩҮЫ•ЫҢЩҶЫҢ|ШҙЫ•Щ…Ы•)/i,
  wide: /^(ЫҢЫ•Ъ© ШҙЫ•Щ…Ы•|ШҜЩҲЩҲ ШҙЫ•Щ…Ы•|ШіЫҺ ШҙЫ•Щ…Ы•|ЪҶЩҲШ§Шұ ШҙЫ•Щ…Ы•|ЩҫЫҺЩҶШ¬ ШҙЫ•Щ…Ы•|ЩҮЫ•ЫҢЩҶЫҢ|ШҙЫ•Щ…Ы•)/i,
};
const parseDayPatterns = {
  narrow: [/^s/i, /^m/i, /^t/i, /^w/i, /^t/i, /^f/i, /^s/i],
  any: [/^su/i, /^m/i, /^tu/i, /^w/i, /^th/i, /^f/i, /^sa/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(Щҫ|ШҜ|ЩҶ-Шҙ|ЩҶ| (ШЁЫ•ЫҢШ§ЩҶЫҢ|ШҜЩҲШ§ЫҢ ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ШҰЫҺЩҲШ§ШұЫ•|ШҙЫ•ЩҲ))/i,
  abbreviated: /^(Щҫ-ЩҶ|ШҜ-ЩҶ|ЩҶЫҢЩҲЫ• ШҙЫ•ЩҲ|ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ШЁЫ•ЫҢШ§ЩҶЫҢ|ШҜЩҲШ§ЫҢ ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ШҰЫҺЩҲШ§ШұЫ•|ШҙЫ•ЩҲ)/,
  wide: /^(ЩҫЫҺШҙ ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ШҜЩҲШ§ЫҢ ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ЩҶЫҢЩҲЫ• ШҙЫ•ЩҲ|Щ„Ы•ШЁЫ•ЫҢШ§ЩҶЫҢШҜШ§|Щ„Ы•ШҜЩҲШ§ЫҢЩҶЫҢЩҲЫ•Ъ•ЫҶШҜШ§|Щ„Ы• ШҰЫҺЩҲШ§ШұЫ•ШҜШ§|Щ„Ы• ШҙЫ•ЩҲШҜШ§)/,
  any: /^(Щҫ|ШҜ|ШЁЫ•ЫҢШ§ЩҶЫҢ|ЩҶЫҢЩҲЫ•Ъ•ЫҶ|ШҰЫҺЩҲШ§ШұЫ•|ШҙЫ•ЩҲ)/,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^ШҜ/i,
    pm: /^Щҫ/i,
    midnight: /^ЩҶ-Шҙ/i,
    noon: /^ЩҶ/i,
    morning: /ШЁЫ•ЫҢШ§ЩҶЫҢ/i,
    afternoon: /ШҜЩҲШ§ЫҢЩҶЫҢЩҲЫ•Ъ•ЫҶ/i,
    evening: /ШҰЫҺЩҲШ§ШұЫ•/i,
    night: /ШҙЫ•ЩҲ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
