const formatRelativeLocale = {
  lastWeek: "'o' eeee 'pasado ГЎ' LT",
  yesterday: "'onte ГЎ' p",
  today: "'hoxe ГЎ' p",
  tomorrow: "'maГұГЎ ГЎ' p",
  nextWeek: "eeee 'ГЎ' p",
  other: "P",
};

const formatRelativeLocalePlural = {
  lastWeek: "'o' eeee 'pasado ГЎs' p",
  yesterday: "'onte ГЎs' p",
  today: "'hoxe ГЎs' p",
  tomorrow: "'maГұГЎ ГЎs' p",
  nextWeek: "eeee 'ГЎs' p",
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  if (date.getHours() !== 1) {
    return formatRelativeLocalePlural[token];
  }
  return formatRelativeLocale[token];
};
