const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "1з§’жңӘжәҖ",
    other: "{{count}}з§’жңӘжәҖ",
    oneWithSuffix: "зҙ„1з§’",
    otherWithSuffix: "зҙ„{{count}}з§’",
  },

  xSeconds: {
    one: "1з§’",
    other: "{{count}}з§’",
  },

  halfAMinute: "30з§’",

  lessThanXMinutes: {
    one: "1еҲҶжңӘжәҖ",
    other: "{{count}}еҲҶжңӘжәҖ",
    oneWithSuffix: "зҙ„1еҲҶ",
    otherWithSuffix: "зҙ„{{count}}еҲҶ",
  },

  xMinutes: {
    one: "1еҲҶ",
    other: "{{count}}еҲҶ",
  },

  aboutXHours: {
    one: "зҙ„1жҷӮй–“",
    other: "зҙ„{{count}}жҷӮй–“",
  },

  xHours: {
    one: "1жҷӮй–“",
    other: "{{count}}жҷӮй–“",
  },

  xDays: {
    one: "1ж—Ҙ",
    other: "{{count}}ж—Ҙ",
  },

  aboutXWeeks: {
    one: "зҙ„1йҖұй–“",
    other: "зҙ„{{count}}йҖұй–“",
  },

  xWeeks: {
    one: "1йҖұй–“",
    other: "{{count}}йҖұй–“",
  },

  aboutXMonths: {
    one: "зҙ„1гҒӢжңҲ",
    other: "зҙ„{{count}}гҒӢжңҲ",
  },

  xMonths: {
    one: "1гҒӢжңҲ",
    other: "{{count}}гҒӢжңҲ",
  },

  aboutXYears: {
    one: "зҙ„1е№ҙ",
    other: "зҙ„{{count}}е№ҙ",
  },

  xYears: {
    one: "1е№ҙ",
    other: "{{count}}е№ҙ",
  },

  overXYears: {
    one: "1е№ҙд»ҘдёҠ",
    other: "{{count}}е№ҙд»ҘдёҠ",
  },

  almostXYears: {
    one: "1е№ҙиҝ‘гҒҸ",
    other: "{{count}}е№ҙиҝ‘гҒҸ",
  },
};

export const formatDistance = (token, count, options) => {
  options = options || {};

  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    if (options.addSuffix && tokenValue.oneWithSuffix) {
      result = tokenValue.oneWithSuffix;
    } else {
      result = tokenValue.one;
    }
  } else {
    if (options.addSuffix && tokenValue.otherWithSuffix) {
      result = tokenValue.otherWithSuffix.replace("{{count}}", String(count));
    } else {
      result = tokenValue.other.replace("{{count}}", String(count));
    }
  }

  if (options.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + "еҫҢ";
    } else {
      return result + "еүҚ";
    }
  }

  return result;
};
