import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(ОҝПӮ|О·|Оҝ)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(ПҖО§|ОјО§)/i,
  abbreviated: /^(ПҖ\.?\s?ПҮ\.?|ПҖ\.?\s?Оә\.?\s?ПҮ\.?|Ој\.?\s?ПҮ\.?|Оә\.?\s?ПҮ\.?)/i,
  wide: /^(ПҖПҒОҝ О§ПҒО№ПғП„Оҝ(ПҚ|П…)|ПҖПҒО№ОҪ ОұПҖ(ПҢ|Оҝ) П„О·ОҪ ОҡОҝО№ОҪ(О®|О·) О§ПҒОҝОҪОҝО»ОҝОі(ОҜ|О№)Оұ|ОјОөП„(О¬|Оұ) О§ПҒО№ПғП„(ПҢ|Оҝ)ОҪ|ОҡОҝО№ОҪ(О®|О·) О§ПҒОҝОҪОҝО»ОҝОі(ОҜ|О№)Оұ)/i,
};
const parseEraPatterns = {
  any: [/^ПҖ/i, /^(Ој|Оә)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^П„[1234]/i,
  wide: /^[1234]Оҝ? П„ПҒ(ОҜ|О№)ОјО·ОҪОҝ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[О№ПҶОјОұОјО№О№ОұПғОҝОҪОҙ]/i,
  abbreviated:
    /^(О№ОұОҪ|ПҶОөОІ|Ој[О¬Оұ]ПҒ|ОұПҖПҒ|Ој[О¬Оұ][О№Оҗ]|О№Оҝ[ПҚП…]ОҪ|О№Оҝ[ПҚП…]О»|Оұ[ПҚП…]Оі|ПғОөПҖ|ОҝОәП„|ОҪОҝ[ОӯОө]|ОҙОөОә)/i,
  wide: /^(Ој[О¬Оұ][О№Оҗ]|Оұ[ПҚП…]ОіОҝ[П…ПҚ]ПғП„)(ОҝПӮ|ОҝП…)|(О№ОұОҪОҝП…[О¬Оұ]ПҒ|ПҶОөОІПҒОҝП…[О¬Оұ]ПҒ|Ој[О¬Оұ]ПҒП„|ОұПҖПҒ[ОҜО№]О»|О№Оҝ[ПҚП…]ОҪ|О№Оҝ[ПҚП…]О»|ПғОөПҖП„[ОӯОө]ОјОІПҒ|ОҝОәП„[ПҺПү]ОІПҒ|ОҪОҝ[ОӯОө]ОјОІПҒ|ОҙОөОә[ОӯОө]ОјОІПҒ)(О№ОҝПӮ|ОҜОҝП…)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^О№/i,
    /^ПҶ/i,
    /^Ој/i,
    /^Оұ/i,
    /^Ој/i,
    /^О№/i,
    /^О№/i,
    /^Оұ/i,
    /^Пғ/i,
    /^Оҝ/i,
    /^ОҪ/i,
    /^Оҙ/i,
  ],

  any: [
    /^О№Оұ/i,
    /^ПҶ/i,
    /^Ој[О¬Оұ]ПҒ/i,
    /^ОұПҖ/i,
    /^Ој[О¬Оұ][О№Оҗ]/i,
    /^О№Оҝ[ПҚП…]ОҪ/i,
    /^О№Оҝ[ПҚП…]О»/i,
    /^Оұ[ПҚП…]/i,
    /^Пғ/i,
    /^Оҝ/i,
    /^ОҪ/i,
    /^Оҙ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ОәОҙП„ПҖПғ]/i,
  short: /^(ОәП…|ОҙОө|П„ПҒ|П„Оө|ПҖ[ОөОӯ]|ПҖ[ОұО¬]|Пғ[ОұО¬])/i,
  abbreviated: /^(ОәП…ПҒ|ОҙОөП…|П„ПҒО№|П„ОөП„|ПҖОөОј|ПҖОұПҒ|ПғОұОІ)/i,
  wide: /^(ОәП…ПҒО№ОұОә(О®|О·)|ОҙОөП…П„(Оӯ|Оө)ПҒОұ|П„ПҒ(ОҜ|О№)П„О·|П„ОөП„(О¬|Оұ)ПҒП„О·|ПҖ(Оӯ|Оө)ОјПҖП„О·|ПҖОұПҒОұПғОәОөП…(О®|О·)|Пғ(О¬|Оұ)ОІОІОұП„Оҝ)/i,
};
const parseDayPatterns = {
  narrow: [/^Оә/i, /^Оҙ/i, /^П„/i, /^П„/i, /^ПҖ/i, /^ПҖ/i, /^Пғ/i],
  any: [/^Оә/i, /^Оҙ/i, /^П„ПҒ/i, /^П„Оө/i, /^ПҖ[ОөОӯ]/i, /^ПҖ[ОұО¬]/i, /^Пғ/i],
};

const matchDayPeriodPatterns = {
  narrow:
    /^(ПҖОј|ОјОј|ОјОөПғ(О¬|Оұ)ОҪП…ПҮП„Оұ|ОјОөПғО·Ој(Оӯ|Оө)ПҒО№|ПҖПҒПү(ОҜ|О№)|ОұПҖ(ПҢ|Оҝ)ОіОөП…ОјОұ|ОІПҒ(О¬|Оұ)ОҙП…|ОҪ(ПҚ|П…)ПҮП„Оұ)/i,
  any: /^([ПҖОј]\.?\s?Ој\.?|ОјОөПғ(О¬|Оұ)ОҪП…ПҮП„Оұ|ОјОөПғО·Ој(Оӯ|Оө)ПҒО№|ПҖПҒПү(ОҜ|О№)|ОұПҖ(ПҢ|Оҝ)ОіОөП…ОјОұ|ОІПҒ(О¬|Оұ)ОҙП…|ОҪ(ПҚ|П…)ПҮП„Оұ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^ПҖОј|ПҖ\.\s?Ој\./i,
    pm: /^ОјОј|Ој\.\s?Ој\./i,
    midnight: /^ОјОөПғО¬ОҪ/i,
    noon: /^ОјОөПғО·Ој(Оӯ|Оө)/i,
    morning: /ПҖПҒПү(ОҜ|О№)/i,
    afternoon: /ОұПҖ(ПҢ|Оҝ)ОіОөП…ОјОұ/i,
    evening: /ОІПҒ(О¬|Оұ)ОҙП…/i,
    night: /ОҪ(ПҚ|П…)ПҮП„Оұ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
