import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?(СҲС–|СҲСӢ))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((Рұ )?Р·\.?\s?Рҙ\.?)/i,
  abbreviated: /^((Рұ )?Р·\.?\s?Рҙ\.?)/i,
  wide: /^(РұС–Р·РҙС–ТЈ Р·Р°РјР°РҪСӢРјСӢР·Т“Р° РҙРөР№С–РҪ|РұС–Р·РҙС–ТЈ Р·Р°РјР°РҪСӢРјСӢР·|РұС–Р·РҙС–ТЈ Р·Р°РјР°РҪСӢРјСӢР·РҙР°РҪ)/i,
};
const parseEraPatterns = {
  any: [/^Рұ/i, /^Р·/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?СҲС–)? СӮРҫТӣ.?/i,
  wide: /^[1234](-?СҲС–)? СӮРҫТӣСҒР°РҪ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(Тӣ|Р°|РҪ|СҒ|Рј|РјР°Сғ|СҲ|СӮ|ТӣСӢСҖ|ТӣР°Р·|ТӣР°СҖ|Р¶)/i,
  abbreviated: /^(ТӣР°ТЈ|Р°ТӣРҝ|РҪР°Сғ|СҒУҷСғ|РјР°Рј|РјР°Сғ|СҲС–Р»|СӮР°Рј|ТӣСӢСҖ|ТӣР°Р·|ТӣР°СҖ|Р¶РөР»)/i,
  wide: /^(ТӣР°ТЈСӮР°СҖ|Р°ТӣРҝР°РҪ|РҪР°СғСҖСӢР·|СҒУҷСғС–СҖ|РјР°РјСӢСҖ|РјР°СғСҒСӢРј|СҲС–Р»РҙРө|СӮР°РјСӢР·|ТӣСӢСҖРәТҜР№РөРә|ТӣР°Р·Р°РҪ|ТӣР°СҖР°СҲР°|Р¶РөР»СӮРҫТӣСҒР°РҪ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^Тӣ/i,
    /^Р°/i,
    /^РҪ/i,
    /^СҒ/i,
    /^Рј/i,
    /^Рј/i,
    /^СҲ/i,
    /^СӮ/i,
    /^Тӣ/i,
    /^Тӣ/i,
    /^Тӣ/i,
    /^Р¶/i,
  ],

  abbreviated: [
    /^ТӣР°ТЈ/i,
    /^Р°ТӣРҝ/i,
    /^РҪР°Сғ/i,
    /^СҒУҷСғ/i,
    /^РјР°Рј/i,
    /^РјР°Сғ/i,
    /^СҲС–Р»/i,
    /^СӮР°Рј/i,
    /^ТӣСӢСҖ/i,
    /^ТӣР°Р·/i,
    /^ТӣР°СҖ/i,
    /^Р¶РөР»/i,
  ],

  any: [
    /^Тӣ/i,
    /^Р°/i,
    /^РҪ/i,
    /^СҒ/i,
    /^Рј/i,
    /^Рј/i,
    /^СҲ/i,
    /^СӮ/i,
    /^Тӣ/i,
    /^Тӣ/i,
    /^Тӣ/i,
    /^Р¶/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(Р¶|Рҙ|СҒ|СҒ|Рұ|Р¶|СҒ)/i,
  short: /^(Р¶СҒ|РҙСҒ|СҒСҒ|СҒСҖ|РұСҒ|Р¶Рј|СҒРұ)/i,
  wide: /^(Р¶РөРәСҒРөРҪРұС–|РҙТҜР№СҒРөРҪРұС–|СҒРөР№СҒРөРҪРұС–|СҒУҷСҖСҒРөРҪРұС–|РұРөР№СҒРөРҪРұС–|Р¶ТұРјР°|СҒРөРҪРұС–)/i,
};
const parseDayPatterns = {
  narrow: [/^Р¶/i, /^Рҙ/i, /^СҒ/i, /^СҒ/i, /^Рұ/i, /^Р¶/i, /^СҒ/i],
  short: [/^Р¶СҒ/i, /^РҙСҒ/i, /^СҒСҒ/i, /^СҒСҖ/i, /^РұСҒ/i, /^Р¶Рј/i, /^СҒРұ/i],
  any: [
    /^Р¶[РөРә]/i,
    /^Рҙ[ТҜР№]/i,
    /^СҒe[Р№]/i,
    /^СҒУҷ[СҖ]/i,
    /^Рұ[РөР№]/i,
    /^Р¶[ТұРј]/i,
    /^СҒРө[РҪ]/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow:
    /^Рў\.?\s?[Р”Рҡ]\.?|СӮТҜРҪ РҫСҖСӮР°СҒСӢРҪРҙР°|((СӮТҜСҒСӮРө|СӮР°ТЈРөСҖСӮРөТЈ|СӮР°ТЈРҙР°|СӮР°ТЈРөСҖСӮРөТЈ|СӮР°ТЈРјРөРҪ|СӮР°ТЈ|РәТҜРҪРҙС–Р·|РәТҜРҪ|РәРөСҲСӮРө|РәРөСҲ|СӮТҜРҪРҙРө|СӮТҜРҪ)\.?)/i,
  wide: /^Рў\.?\s?[Р”Рҡ]\.?|СӮТҜРҪ РҫСҖСӮР°СҒСӢРҪРҙР°|((СӮТҜСҒСӮРө|СӮР°ТЈРөСҖСӮРөТЈ|СӮР°ТЈРҙР°|СӮР°ТЈРөСҖСӮРөТЈ|СӮР°ТЈРјРөРҪ|СӮР°ТЈ|РәТҜРҪРҙС–Р·|РәТҜРҪ|РәРөСҲСӮРө|РәРөСҲ|СӮТҜРҪРҙРө|СӮТҜРҪ)\.?)/i,
  any: /^Рў\.?\s?[Р”Рҡ]\.?|СӮТҜРҪ РҫСҖСӮР°СҒСӢРҪРҙР°|((СӮТҜСҒСӮРө|СӮР°ТЈРөСҖСӮРөТЈ|СӮР°ТЈРҙР°|СӮР°ТЈРөСҖСӮРөТЈ|СӮР°ТЈРјРөРҪ|СӮР°ТЈ|РәТҜРҪРҙС–Р·|РәТҜРҪ|РәРөСҲСӮРө|РәРөСҲ|СӮТҜРҪРҙРө|СӮТҜРҪ)\.?)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^РўР”/i,
    pm: /^РўРҡ/i,
    midnight: /^СӮТҜРҪ РҫСҖСӮР°/i,
    noon: /^РәТҜРҪРҙС–Р·/i,
    morning: /СӮР°ТЈ/i,
    afternoon: /СӮТҜСҒ/i,
    evening: /РәРөСҲ/i,
    night: /СӮТҜРҪ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
