import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /\d+/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(РҪСӮУ©|РҪСӮ)/i,
  abbreviated: /^(РҪСӮУ©|РҪСӮ)/i,
  wide: /^(РҪРёР№СӮРёР№РҪ СӮРҫРҫР»Р»СӢРҪ У©РјРҪУ©|РҪРёР№СӮРёР№РҪ СӮРҫРҫР»Р»СӢРҪ)/i,
};
const parseEraPatterns = {
  any: [/^(РҪСӮУ©|РҪРёР№СӮРёР№РҪ СӮРҫРҫР»Р»СӢРҪ У©РјРҪУ©)/i, /^(РҪСӮ|РҪРёР№СӮРёР№РҪ СӮРҫРҫР»Р»СӢРҪ)/i],
};

const matchQuarterPatterns = {
  narrow: /^(iv|iii|ii|i)/i,
  abbreviated: /^(iv|iii|ii|i) СғР»РёСҖР°Р»/i,
  wide: /^[1-4]-СҖ СғР»РёСҖР°Р»/i,
};
const parseQuarterPatterns = {
  any: [/^(i(\s|$)|1)/i, /^(ii(\s|$)|2)/i, /^(iii(\s|$)|3)/i, /^(iv(\s|$)|4)/i],
};

const matchMonthPatterns = {
  narrow: /^(xii|xi|x|ix|viii|vii|vi|v|iv|iii|ii|i)/i,
  abbreviated:
    /^(1-СҖ СҒР°СҖ|2-СҖ СҒР°СҖ|3-СҖ СҒР°СҖ|4-СҖ СҒР°СҖ|5-СҖ СҒР°СҖ|6-СҖ СҒР°СҖ|7-СҖ СҒР°СҖ|8-СҖ СҒР°СҖ|9-СҖ СҒР°СҖ|10-СҖ СҒР°СҖ|11-СҖ СҒР°СҖ|12-СҖ СҒР°СҖ)/i,
  wide: /^(РҪСҚРіРҙТҜРіСҚСҚСҖ СҒР°СҖ|С…РҫС‘СҖРҙСғРіР°Р°СҖ СҒР°СҖ|РіСғСҖР°РІРҙСғРіР°Р°СҖ СҒР°СҖ|РҙУ©СҖУ©РІРҙТҜРіСҚСҚСҖ СҒР°СҖ|СӮР°РІРҙСғРіР°Р°СҖ СҒР°СҖ|Р·СғСҖРіР°Р°РҙСғРіР°Р°СҖ СҒР°СҖ|РҙРҫР»РҫРҫРҙСғРіР°Р°СҖ СҒР°СҖ|РҪР°Р№РјРҙСғРіР°Р°СҖ СҒР°СҖ|РөСҒРҙТҜРіСҚСҚСҖ СҒР°СҖ|Р°СҖР°РІРҙСғРіР°Р°СҖ СҒР°СҖ|Р°СҖРІР°РҪ РҪСҚРіРҙТҜРіСҚСҚСҖ СҒР°СҖ|Р°СҖРІР°РҪ С…РҫС‘СҖРҙСғРіР°Р°СҖ СҒР°СҖ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^i$/i,
    /^ii$/i,
    /^iii$/i,
    /^iv$/i,
    /^v$/i,
    /^vi$/i,
    /^vii$/i,
    /^viii$/i,
    /^ix$/i,
    /^x$/i,
    /^xi$/i,
    /^xii$/i,
  ],

  any: [
    /^(1|РҪСҚРіРҙТҜРіСҚСҚСҖ)/i,
    /^(2|С…РҫС‘СҖРҙСғРіР°Р°СҖ)/i,
    /^(3|РіСғСҖР°РІРҙСғРіР°Р°СҖ)/i,
    /^(4|РҙУ©СҖУ©РІРҙТҜРіСҚСҚСҖ)/i,
    /^(5|СӮР°РІРҙСғРіР°Р°СҖ)/i,
    /^(6|Р·СғСҖРіР°Р°РҙСғРіР°Р°СҖ)/i,
    /^(7|РҙРҫР»РҫРҫРҙСғРіР°Р°СҖ)/i,
    /^(8|РҪР°Р№РјРҙСғРіР°Р°СҖ)/i,
    /^(9|РөСҒРҙТҜРіСҚСҚСҖ)/i,
    /^(10|Р°СҖР°РІРҙСғРіР°Р°СҖ)/i,
    /^(11|Р°СҖРІР°РҪ РҪСҚРіРҙТҜРіСҚСҚСҖ)/i,
    /^(12|Р°СҖРІР°РҪ С…РҫС‘СҖРҙСғРіР°Р°СҖ)/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[РҪРҙРјР»РҝРұРұ]/i,
  short: /^(РҪСҸ|РҙР°|РјСҸ|Р»С…|РҝТҜ|РұР°|РұСҸ)/i,
  abbreviated: /^(РҪСҸРј|РҙР°РІ|РјСҸРі|Р»С…Р°|РҝТҜСҖ|РұР°Р°|РұСҸРј)/i,
  wide: /^(РҪСҸРј|РҙР°РІР°Р°|РјСҸРіРјР°СҖ|Р»С…Р°РіРІР°|РҝТҜСҖСҚРІ|РұР°Р°СҒР°РҪ|РұСҸРјРұР°)/i,
};
const parseDayPatterns = {
  narrow: [/^РҪ/i, /^Рҙ/i, /^Рј/i, /^Р»/i, /^Рҝ/i, /^Рұ/i, /^Рұ/i],
  any: [/^РҪСҸ/i, /^РҙР°/i, /^РјСҸ/i, /^Р»С…/i, /^РҝТҜ/i, /^РұР°/i, /^РұСҸ/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(ТҜ\.У©\.|ТҜ\.С…\.|СҲУ©РҪУ© РҙСғРҪРҙ|ТҜРҙ РҙСғРҪРҙ|У©РіР»У©У©|У©РҙУ©СҖ|РҫСҖРҫР№|СҲУ©РҪУ©)/i,
  any: /^(ТҜ\.У©\.|ТҜ\.С…\.|СҲУ©РҪУ© РҙСғРҪРҙ|ТҜРҙ РҙСғРҪРҙ|У©РіР»У©У©|У©РҙУ©СҖ|РҫСҖРҫР№|СҲУ©РҪУ©)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^ТҜ\.У©\./i,
    pm: /^ТҜ\.С…\./i,
    midnight: /^СҲУ©РҪУ© РҙСғРҪРҙ/i,
    noon: /^ТҜРҙ РҙСғРҪРҙ/i,
    morning: /У©РіР»У©У©/i,
    afternoon: /У©РҙУ©СҖ/i,
    evening: /РҫСҖРҫР№/i,
    night: /СҲУ©РҪУ©/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
