const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "mГ« pak se njГ« sekondГ«",
    other: "mГ« pak se {{count}} sekonda",
  },

  xSeconds: {
    one: "1 sekondГ«",
    other: "{{count}} sekonda",
  },

  halfAMinute: "gjysГ«m minuti",

  lessThanXMinutes: {
    one: "mГ« pak se njГ« minute",
    other: "mГ« pak se {{count}} minuta",
  },

  xMinutes: {
    one: "1 minutГ«",
    other: "{{count}} minuta",
  },

  aboutXHours: {
    one: "rreth 1 orГ«",
    other: "rreth {{count}} orГ«",
  },

  xHours: {
    one: "1 orГ«",
    other: "{{count}} orГ«",
  },

  xDays: {
    one: "1 ditГ«",
    other: "{{count}} ditГ«",
  },

  aboutXWeeks: {
    one: "rreth 1 javГ«",
    other: "rreth {{count}} javГ«",
  },

  xWeeks: {
    one: "1 javГ«",
    other: "{{count}} javГ«",
  },

  aboutXMonths: {
    one: "rreth 1 muaj",
    other: "rreth {{count}} muaj",
  },

  xMonths: {
    one: "1 muaj",
    other: "{{count}} muaj",
  },

  aboutXYears: {
    one: "rreth 1 vit",
    other: "rreth {{count}} vite",
  },

  xYears: {
    one: "1 vit",
    other: "{{count}} vite",
  },

  overXYears: {
    one: "mbi 1 vit",
    other: "mbi {{count}} vite",
  },

  almostXYears: {
    one: "pothuajse 1 vit",
    other: "pothuajse {{count}} vite",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "nГ« " + result;
    } else {
      return result + " mГ« parГ«";
    }
  }

  return result;
};
