import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)\.?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(p[Еҷr](\.|ed) Kr\.|p[Еҷr](\.|ed) n\. l\.|po Kr\.|n\. l\.)/i,
  abbreviated: /^(p[Еҷr](\.|ed) Kr\.|p[Еҷr](\.|ed) n\. l\.|po Kr\.|n\. l\.)/i,
  wide: /^(p[Еҷr](\.|ed) Kristem|p[Еҷr](\.|ed) na[ЕЎs][Гӯi]m letopo[ДҚc]tem|po Kristu|na[ЕЎs]eho letopo[ДҚc]tu)/i,
};

const parseEraPatterns = {
  any: [/^p[Еҷr]/i, /^(po|n)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]\. [ДҚc]tvrtlet[Гӯi]/i,
  wide: /^[1234]\. [ДҚc]tvrtlet[Гӯi]/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[lГәubdkДҚcszЕҷrlp]/i,
  abbreviated:
    /^(led|[Гәu]no|b[Еҷr]e|dub|kv[Дӣe]|[ДҚc]vn|[ДҚc]vc|srp|z[ГЎa][Еҷr]|[Еҷr][Гӯi]j|lis|pro)/i,
  wide: /^(leden|ledna|[Гәu]nora?|b[Еҷr]ezen|b[Еҷr]ezna|duben|dubna|kv[Дӣe]ten|kv[Дӣe]tna|[ДҚc]erven(ec|ce)?|[ДҚc]ervna|srpen|srpna|z[ГЎa][Еҷr][Гӯi]|[Еҷr][Гӯi]jen|[Еҷr][Гӯi]jna|listopad(a|u)?|prosinec|prosince)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^l/i,
    /^[Гәu]/i,
    /^b/i,
    /^d/i,
    /^k/i,
    /^[ДҚc]/i,
    /^[ДҚc]/i,
    /^s/i,
    /^z/i,
    /^[Еҷr]/i,
    /^l/i,
    /^p/i,
  ],

  any: [
    /^led/i,
    /^[Гәu]n/i,
    /^b[Еҷr]e/i,
    /^dub/i,
    /^kv[Дӣe]/i,
    /^[ДҚc]vn|[ДҚc]erven(?!\w)|[ДҚc]ervna/i,
    /^[ДҚc]vc|[ДҚc]erven(ec|ce)/i,
    /^srp/i,
    /^z[ГЎa][Еҷr]/i,
    /^[Еҷr][Гӯi]j/i,
    /^lis/i,
    /^pro/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[npuГәsДҚps]/i,
  short: /^(ne|po|[Гәu]t|st|[ДҚc]t|p[ГЎa]|so)/i,
  abbreviated: /^(ned|pon|[Гәu]te|st[rЕҷ]|[ДҚc]tv|p[ГЎa]t|sob)/i,
  wide: /^(ned[Дӣe]le|pond[Дӣe]l[Гӯi]|[Гәu]ter[ГҪy]|st[Еҷr]eda|[ДҚc]tvrtek|p[ГЎa]tek|sobota)/i,
};

const parseDayPatterns = {
  narrow: [/^n/i, /^p/i, /^[Гәu]/i, /^s/i, /^[ДҚc]/i, /^p/i, /^s/i],
  any: [/^ne/i, /^po/i, /^[Гәu]t/i, /^st/i, /^[ДҚc]t/i, /^p[ГЎa]/i, /^so/i],
};

const matchDayPeriodPatterns = {
  any: /^dopoledne|dop\.?|odpoledne|odp\.?|p[ЕҜu]lnoc|poledne|r[ГЎa]no|odpoledne|ve[ДҚc]er|(v )?noci?/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^dop/i,
    pm: /^odp/i,
    midnight: /^p[ЕҜu]lnoc/i,
    noon: /^poledne/i,
    morning: /r[ГЎa]no/i,
    afternoon: /odpoledne/i,
    evening: /ve[ДҚc]er/i,
    night: /noc/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
