import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?(Рө|Р№|С”|Р°|СҸ))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((РҙРҫ )?РҪ\.?\s?Рө\.?)/i,
  abbreviated: /^((РҙРҫ )?РҪ\.?\s?Рө\.?)/i,
  wide: /^(РҙРҫ РҪР°СҲРҫС— РөСҖРё|РҪР°СҲРҫС— РөСҖРё|РҪР°СҲР° РөСҖР°)/i,
};

const parseEraPatterns = {
  any: [/^Рҙ/i, /^РҪ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[РёС–]?Р№?)? РәРІ.?/i,
  wide: /^[1234](-?[РёС–]?Р№?)? РәРІР°СҖСӮР°Р»/i,
};

const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[СҒР»РұРәСӮСҮРІР¶Рі]/i,
  abbreviated:
    /^(СҒС–СҮ|Р»СҺСӮ|РұРөСҖ(РөР·)?|РәРІС–СӮ|СӮСҖР°РІ|СҮРөСҖРІ|Р»РёРҝ|СҒРөСҖРҝ|РІРөСҖ(РөСҒ)?|Р¶РҫРІСӮ|Р»РёСҒ(СӮРҫРҝ)?|РіСҖСғРҙ)\.?/i,
  wide: /^(СҒС–СҮРөРҪСҢ|СҒС–СҮРҪСҸ|Р»СҺСӮРёР№|Р»СҺСӮРҫРіРҫ|РұРөСҖРөР·РөРҪСҢ|РұРөСҖРөР·РҪСҸ|РәРІС–СӮРөРҪСҢ|РәРІС–СӮРҪСҸ|СӮСҖР°РІРөРҪСҢ|СӮСҖР°РІРҪСҸ|СҮРөСҖРІРҪСҸ|СҮРөСҖРІРөРҪСҢ|Р»РёРҝРөРҪСҢ|Р»РёРҝРҪСҸ|СҒРөСҖРҝРөРҪСҢ|СҒРөСҖРҝРҪСҸ|РІРөСҖРөСҒРөРҪСҢ|РІРөСҖРөСҒРҪСҸ|Р¶РҫРІСӮРөРҪСҢ|Р¶РҫРІСӮРҪСҸ|Р»РёСҒСӮРҫРҝР°Рҙ[Р°]?|РіСҖСғРҙРөРҪСҢ|РіСҖСғРҙРҪСҸ)/i,
};

const parseMonthPatterns = {
  narrow: [
    /^СҒ/i,
    /^Р»/i,
    /^Рұ/i,
    /^Рә/i,
    /^СӮ/i,
    /^СҮ/i,
    /^Р»/i,
    /^СҒ/i,
    /^РІ/i,
    /^Р¶/i,
    /^Р»/i,
    /^Рі/i,
  ],

  any: [
    /^СҒС–/i,
    /^Р»СҺ/i,
    /^Рұ/i,
    /^Рә/i,
    /^СӮ/i,
    /^СҮ/i,
    /^Р»РёРҝ/i,
    /^СҒРө/i,
    /^РІ/i,
    /^Р¶/i,
    /^Р»РёСҒ/i,
    /^Рі/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[РҪРҝРІСҒСҮ]/i,
  short: /^(РҪРҙ|РҝРҪ|РІСӮ|СҒСҖ|СҮСӮ|РҝСӮ|СҒРұ)\.?/i,
  abbreviated: /^(РҪРөРҙ|РҝРҫРҪ|РІС–РІ|СҒРөСҖ|СҮРө?СӮРІ|РҝСӮРҪ?|СҒСғРұ)\.?/i,
  wide: /^(РҪРөРҙС–Р»[СҸС–]|РҝРҫРҪРөРҙС–Р»[РҫРә][РәР°]|РІС–РІСӮРҫСҖ[РҫРә][РәР°]|СҒРөСҖРөРҙ[Р°Рё]|СҮРөСӮРІРөСҖ(РіР°)?|Рҝ\W*?СҸСӮРҪРёСҶ[СҸС–]|СҒСғРұРҫСӮ[Р°Рё])/i,
};

const parseDayPatterns = {
  narrow: [/^РҪ/i, /^Рҝ/i, /^РІ/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^СҒ/i],
  any: [/^РҪ/i, /^Рҝ[РҫРҪ]/i, /^РІ/i, /^СҒ[РөСҖ]/i, /^СҮ/i, /^Рҝ\W*?[СҸСӮ]/i, /^СҒ[СғРұ]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([РҙРҝ]Рҝ|РҝС–РІРҪ\.?|РҝРҫР»\.?|СҖР°РҪРҫРә|СҖР°РҪРәСғ|РҙРөРҪСҢ|РҙРҪСҸ|РІРөСҮ\.?|РҪС–СҮ|РҪРҫСҮС–)/i,
  abbreviated: /^([РҙРҝ]Рҝ|РҝС–РІРҪ\.?|РҝРҫР»\.?|СҖР°РҪРҫРә|СҖР°РҪРәСғ|РҙРөРҪСҢ|РҙРҪСҸ|РІРөСҮ\.?|РҪС–СҮ|РҪРҫСҮС–)/i,
  wide: /^([РҙРҝ]Рҝ|РҝС–РІРҪС–СҮ|РҝРҫР»СғРҙРөРҪСҢ|СҖР°РҪРҫРә|СҖР°РҪРәСғ|РҙРөРҪСҢ|РҙРҪСҸ|РІРөСҮС–СҖ|РІРөСҮРҫСҖР°|РҪС–СҮ|РҪРҫСҮС–)/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^РҙРҝ/i,
    pm: /^РҝРҝ/i,
    midnight: /^РҝС–РІРҪ/i,
    noon: /^РҝРҫР»/i,
    morning: /^СҖ/i,
    afternoon: /^Рҙ[РөРҪ]/i,
    evening: /^РІ/i,
    night: /^РҪ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
