const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);

  switch (options?.unit) {
    case "date":
      return number.toString() + "ж—Ҙ";
    case "hour":
      return number.toString() + "ж—¶";
    case "minute":
      return number.toString() + "еҲҶ";
    case "second":
      return number.toString() + "з§’";
    default:
      return "з¬¬ " + number.toString();
  }
};

