const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "bir saniyЙҷdЙҷn az",
    other: "{{count}} bir saniyЙҷdЙҷn az",
  },

  xSeconds: {
    one: "1 saniyЙҷ",
    other: "{{count}} saniyЙҷ",
  },

  halfAMinute: "yarДұm dЙҷqiqЙҷ",

  lessThanXMinutes: {
    one: "bir dЙҷqiqЙҷdЙҷn az",
    other: "{{count}} bir dЙҷqiqЙҷdЙҷn az",
  },

  xMinutes: {
    one: "bir dЙҷqiqЙҷ",
    other: "{{count}} dЙҷqiqЙҷ",
  },

  aboutXHours: {
    one: "tЙҷxminЙҷn 1 saat",
    other: "tЙҷxminЙҷn {{count}} saat",
  },

  xHours: {
    one: "1 saat",
    other: "{{count}} saat",
  },

  xDays: {
    one: "1 gГјn",
    other: "{{count}} gГјn",
  },

  aboutXWeeks: {
    one: "tЙҷxminЙҷn 1 hЙҷftЙҷ",
    other: "tЙҷxminЙҷn {{count}} hЙҷftЙҷ",
  },

  xWeeks: {
    one: "1 hЙҷftЙҷ",
    other: "{{count}} hЙҷftЙҷ",
  },

  aboutXMonths: {
    one: "tЙҷxminЙҷn 1 ay",
    other: "tЙҷxminЙҷn {{count}} ay",
  },

  xMonths: {
    one: "1 ay",
    other: "{{count}} ay",
  },

  aboutXYears: {
    one: "tЙҷxminЙҷn 1 il",
    other: "tЙҷxminЙҷn {{count}} il",
  },

  xYears: {
    one: "1 il",
    other: "{{count}} il",
  },

  overXYears: {
    one: "1 ildЙҷn Г§ox",
    other: "{{count}} ildЙҷn Г§ox",
  },

  almostXYears: {
    one: "demЙҷk olar ki 1 il",
    other: "demЙҷk olar ki {{count}} il",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + " sonra";
    } else {
      return result + " ЙҷvvЙҷl";
    }
  }

  return result;
};
