import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern =
  /^(\d+|(ЧЁЧҗЧ©Ч•Чҹ|Ч©Ч Чҷ|Ч©ЧңЧҷЧ©Чҷ|ЧЁЧ‘ЧҷЧўЧҷ|Ч—ЧһЧҷЧ©Чҷ|Ч©ЧҷЧ©Чҷ|Ч©Ч‘ЧҷЧўЧҷ|Ч©ЧһЧҷЧ Чҷ|ЧӘЧ©ЧҷЧўЧҷ|ЧўЧ©ЧҷЧЁЧҷ|ЧЁЧҗЧ©Ч•Ч Ч”|Ч©Ч ЧҷЧҷЧ”|Ч©ЧңЧҷЧ©ЧҷЧӘ|ЧЁЧ‘ЧҷЧўЧҷЧӘ|Ч—ЧһЧҷЧ©ЧҷЧӘ|Ч©ЧҷЧ©ЧҷЧӘ|Ч©Ч‘ЧҷЧўЧҷЧӘ|Ч©ЧһЧҷЧ ЧҷЧӘ|ЧӘЧ©ЧҷЧўЧҷЧӘ|ЧўЧ©ЧҷЧЁЧҷЧӘ))/i;
const parseOrdinalNumberPattern = /^(\d+|ЧЁЧҗ|Ч©Ч |Ч©Чң|ЧЁЧ‘|Ч—|Ч©Чҷ|Ч©Ч‘|Ч©Чһ|ЧӘ|Чў)/i;

const matchEraPatterns = {
  narrow: /^Чң(ЧЎЧӨЧҷЧЁЧ”|ЧӨЧ Ч”ЧҙЧЎ)/i,
  abbreviated: /^Чң(ЧЎЧӨЧҷЧЁЧ”|ЧӨЧ Ч”ЧҙЧЎ)/i,
  wide: /^Чң(ЧӨЧ Чҷ Ч”)?ЧЎЧӨЧҷЧЁЧ”/i,
};
const parseEraPatterns = {
  any: [/^ЧңЧӨ/i, /^ЧңЧЎ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^q[1234]/i,
  wide: /^ЧЁЧ‘ЧўЧ•Чҹ [1234]/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^\d+/i,
  abbreviated: /^(ЧҷЧ Ч•|ЧӨЧ‘ЧЁ|ЧһЧЁЧҘ|ЧҗЧӨЧЁ|ЧһЧҗЧҷ|ЧҷЧ•Ч Чҷ|ЧҷЧ•ЧңЧҷ|ЧҗЧ•Ч’|ЧЎЧӨЧҳ|ЧҗЧ•Ч§|Ч Ч•Ч‘|Ч“ЧҰЧһ)Чі?/i,
  wide: /^(ЧҷЧ Ч•ЧҗЧЁ|ЧӨЧ‘ЧЁЧ•ЧҗЧЁ|ЧһЧЁЧҘ|ЧҗЧӨЧЁЧҷЧң|ЧһЧҗЧҷ|ЧҷЧ•Ч Чҷ|ЧҷЧ•ЧңЧҷ|ЧҗЧ•Ч’Ч•ЧЎЧҳ|ЧЎЧӨЧҳЧһЧ‘ЧЁ|ЧҗЧ•Ч§ЧҳЧ•Ч‘ЧЁ|Ч Ч•Ч‘ЧһЧ‘ЧЁ|Ч“ЧҰЧһЧ‘ЧЁ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^1$/i,
    /^2/i,
    /^3/i,
    /^4/i,
    /^5/i,
    /^6/i,
    /^7/i,
    /^8/i,
    /^9/i,
    /^10/i,
    /^11/i,
    /^12/i,
  ],

  any: [
    /^ЧҷЧ /i,
    /^ЧӨ/i,
    /^ЧһЧЁ/i,
    /^ЧҗЧӨ/i,
    /^ЧһЧҗ/i,
    /^ЧҷЧ•Ч /i,
    /^ЧҷЧ•Чң/i,
    /^ЧҗЧ•Ч’/i,
    /^ЧЎ/i,
    /^ЧҗЧ•Ч§/i,
    /^Ч /i,
    /^Ч“/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ЧҗЧ‘Ч’Ч“Ч”Ч•Ч©]Чі/i,
  short: /^[ЧҗЧ‘Ч’Ч“Ч”Ч•Ч©]Чі/i,
  abbreviated: /^(Ч©Ч‘ЧӘ|ЧҷЧ•Чқ (Чҗ|Ч‘|Ч’|Ч“|Ч”|Ч•)Чі)/i,
  wide: /^ЧҷЧ•Чқ (ЧЁЧҗЧ©Ч•Чҹ|Ч©Ч Чҷ|Ч©ЧңЧҷЧ©Чҷ|ЧЁЧ‘ЧҷЧўЧҷ|Ч—ЧһЧҷЧ©Чҷ|Ч©ЧҷЧ©Чҷ|Ч©Ч‘ЧӘ)/i,
};
const parseDayPatterns = {
  abbreviated: [/ЧҗЧі$/i, /Ч‘Чі$/i, /Ч’Чі$/i, /Ч“Чі$/i, /Ч”Чі$/i, /Ч•Чі$/i, /^Ч©/i],
  wide: [/Чҹ$/i, /Ч Чҷ$/i, /ЧңЧҷЧ©Чҷ$/i, /ЧўЧҷ$/i, /ЧһЧҷЧ©Чҷ$/i, /Ч©ЧҷЧ©Чҷ$/i, /ЧӘ$/i],
  any: [/^Чҗ/i, /^Ч‘/i, /^Ч’/i, /^Ч“/i, /^Ч”/i, /^Ч•/i, /^Ч©/i],
};

const matchDayPeriodPatterns = {
  any: /^(ЧҗЧ—ЧЁ Ч”|Ч‘)?(Ч—ЧҰЧ•ЧӘ|ЧҰЧ”ЧЁЧҷЧҷЧқ|Ч‘Ч•Ч§ЧЁ|ЧўЧЁЧ‘|ЧңЧҷЧңЧ”|ЧҗЧ—Ч”ЧҙЧҰ|ЧңЧӨЧ Ч”ЧҙЧҰ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^ЧңЧӨ/i,
    pm: /^ЧҗЧ—Ч”/i,
    midnight: /^Ч—/i,
    noon: /^ЧҰ/i,
    morning: /Ч‘Ч•Ч§ЧЁ/i,
    afternoon: /Ч‘ЧҰ|ЧҗЧ—ЧЁ/i,
    evening: /ЧўЧЁЧ‘/i,
    night: /ЧңЧҷЧңЧ”/i,
  },
};

const ordinalName = ["ЧЁЧҗ", "Ч©Ч ", "Ч©Чң", "ЧЁЧ‘", "Ч—", "Ч©Чҷ", "Ч©Ч‘", "Ч©Чһ", "ЧӘ", "Чў"];

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => {
      const number = parseInt(value, 10);
      return isNaN(number) ? ordinalName.indexOf(value) + 1 : number;
    },
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
