const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "е°‘ж–ј 1 з§’",
    other: "е°‘ж–ј {{count}} з§’",
  },

  xSeconds: {
    one: "1 з§’",
    other: "{{count}} з§’",
  },

  halfAMinute: "еҚҠеҲҶйҗҳ",

  lessThanXMinutes: {
    one: "е°‘ж–ј 1 еҲҶйҗҳ",
    other: "е°‘ж–ј {{count}} еҲҶйҗҳ",
  },

  xMinutes: {
    one: "1 еҲҶйҗҳ",
    other: "{{count}} еҲҶйҗҳ",
  },

  xHours: {
    one: "1 е°ҸжҷӮ",
    other: "{{count}} е°ҸжҷӮ",
  },

  aboutXHours: {
    one: "еӨ§зҙ„ 1 е°ҸжҷӮ",
    other: "еӨ§зҙ„ {{count}} е°ҸжҷӮ",
  },

  xDays: {
    one: "1 еӨ©",
    other: "{{count}} еӨ©",
  },

  aboutXWeeks: {
    one: "еӨ§зҙ„ 1 еҖӢжҳҹжңҹ",
    other: "еӨ§зҙ„ {{count}} еҖӢжҳҹжңҹ",
  },

  xWeeks: {
    one: "1 еҖӢжҳҹжңҹ",
    other: "{{count}} еҖӢжҳҹжңҹ",
  },

  aboutXMonths: {
    one: "еӨ§зҙ„ 1 еҖӢжңҲ",
    other: "еӨ§зҙ„ {{count}} еҖӢжңҲ",
  },

  xMonths: {
    one: "1 еҖӢжңҲ",
    other: "{{count}} еҖӢжңҲ",
  },

  aboutXYears: {
    one: "еӨ§зҙ„ 1 е№ҙ",
    other: "еӨ§зҙ„ {{count}} е№ҙ",
  },

  xYears: {
    one: "1 е№ҙ",
    other: "{{count}} е№ҙ",
  },

  overXYears: {
    one: "и¶…йҒҺ 1 е№ҙ",
    other: "и¶…йҒҺ {{count}} е№ҙ",
  },

  almostXYears: {
    one: "е°Үиҝ‘ 1 е№ҙ",
    other: "е°Үиҝ‘ {{count}} е№ҙ",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + "е…§";
    } else {
      return result + "еүҚ";
    }
  }

  return result;
};
