import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)/;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(ЩӮ|ШЁ)/g,
  abbreviated: /^(ЩӮ.Щ…|ШЁ.Щ…)/g,
  wide: /^(ЩӮШЁЩ„ Ш§Щ„Щ…ЩҠЩ„Ш§ШҜ|ШЁШ№ШҜ Ш§Щ„Щ…ЩҠЩ„Ш§ШҜ)/g,
};
const parseEraPatterns = {
  any: [/^ЩӮ/g, /^ШЁ/g],
};
const matchQuarterPatterns = {
  narrow: /^[1234]/,
  abbreviated: /^Шұ[1234]/,
  wide: /^Ш§Щ„ШұШЁШ№ (Ш§Щ„ШЈЩҲЩ„|Ш§Щ„Ш«Ш§ЩҶЩҠ|Ш§Щ„Ш«Ш§Щ„Ш«|Ш§Щ„ШұШ§ШЁШ№)/,
};
const parseQuarterPatterns = {
  wide: [/Ш§Щ„ШұШЁШ№ Ш§Щ„ШЈЩҲЩ„/, /Ш§Щ„ШұШЁШ№ Ш§Щ„Ш«Ш§ЩҶЩҠ/, /Ш§Щ„ШұШЁШ№ Ш§Щ„Ш«Ш§Щ„Ш«/, /Ш§Щ„ШұШЁШ№ Ш§Щ„ШұШ§ШЁШ№/],

  any: [/1/, /2/, /3/, /4/],
};

const matchMonthPatterns = {
  narrow: /^(ЩҠ|ЩҒ|Щ…|ШЈ|Ші|ЩҶ|ШҜ)/,
  abbreviated: /^(ЩҠЩҶШ§|ЩҒШЁШұ|Щ…Ш§ШұШі|ШЈШЁШұЩҠЩ„|Щ…Ш§ЩҠЩҲ|ЩҠЩҲЩҶЩҖ|ЩҠЩҲЩ„ЩҖ|ШЈШәШіЩҖ|ШіШЁШӘЩҖ|ШЈЩғШӘЩҖ|ЩҶЩҲЩҒЩҖ|ШҜЩҠШіЩҖ)/,
  wide: /^(ЩҠЩҶШ§ЩҠШұ|ЩҒШЁШұШ§ЩҠШұ|Щ…Ш§ШұШі|ШЈШЁШұЩҠЩ„|Щ…Ш§ЩҠЩҲ|ЩҠЩҲЩҶЩҠЩҲ|ЩҠЩҲЩ„ЩҠЩҲ|ШЈШәШіШ·Ші|ШіШЁШӘЩ…ШЁШұ|ШЈЩғШӘЩҲШЁШұ|ЩҶЩҲЩҒЩ…ШЁШұ|ШҜЩҠШіЩ…ШЁШұ)/,
};
const parseMonthPatterns = {
  narrow: [
    /^ЩҠ/,
    /^ЩҒ/,
    /^Щ…/,
    /^ШЈ/,
    /^Щ…/,
    /^ЩҠ/,
    /^ЩҠ/,
    /^ШЈ/,
    /^Ші/,
    /^ШЈ/,
    /^ЩҶ/,
    /^ШҜ/,
  ],

  any: [
    /^ЩҠЩҶШ§/,
    /^ЩҒШЁШұ/,
    /^Щ…Ш§ШұШі/,
    /^ШЈШЁШұЩҠЩ„/,
    /^Щ…Ш§ЩҠЩҲ/,
    /^ЩҠЩҲЩҶ/,
    /^ЩҠЩҲЩ„/,
    /^ШЈШәШі/,
    /^ШіШЁШӘ/,
    /^ШЈЩғШӘ/,
    /^ЩҶЩҲЩҒ/,
    /^ШҜЩҠШі/,
  ],
};

const matchDayPatterns = {
  narrow: /^(Шӯ|ЩҶ|Ш«|Шұ|Ш®|Ш¬|Ші)/,
  short: /^(ШЈШӯШҜ|Ш§Ш«ЩҶЩҠЩҶ|Ш«Щ„Ш§Ш«Ш§ШЎ|ШЈШұШЁШ№Ш§ШЎ|Ш®Щ…ЩҠШі|Ш¬Щ…Ш№Ш©|ШіШЁШӘ)/,
  abbreviated: /^(ШЈШӯШҜ|Ш§Ш«ЩҶЩҠЩҶ|Ш«Щ„Ш§Ш«Ш§ШЎ|ШЈШұШЁШ№Ш§ШЎ|Ш®Щ…ЩҠШі|Ш¬Щ…Ш№Ш©|ШіШЁШӘ)/,
  wide: /^(Ш§Щ„ШЈШӯШҜ|Ш§Щ„Ш§Ш«ЩҶЩҠЩҶ|Ш§Щ„Ш«Щ„Ш§Ш«Ш§ШЎ|Ш§Щ„ШЈШұШЁШ№Ш§ШЎ|Ш§Щ„Ш®Щ…ЩҠШі|Ш§Щ„Ш¬Щ…Ш№Ш©|Ш§Щ„ШіШЁШӘ)/,
};
const parseDayPatterns = {
  narrow: [/^Шӯ/, /^ЩҶ/, /^Ш«/, /^Шұ/, /^Ш®/, /^Ш¬/, /^Ші/],
  any: [/ШЈШӯШҜ/, /Ш§Ш«ЩҶЩҠЩҶ/, /Ш«Щ„Ш§Ш«Ш§ШЎ/, /ШЈШұШЁШ№Ш§ШЎ/, /Ш®Щ…ЩҠШі/, /Ш¬Щ…Ш№Ш©/, /ШіШЁШӘ/],
};

const matchDayPeriodPatterns = {
  narrow: /^(Шө|Щ…|ЩҶ|Шё|ЩҒЩҠ Ш§Щ„ШөШЁШ§Шӯ|ШЁШ№ШҜ Ш§Щ„ШёЩҮШұ|ЩҒЩҠ Ш§Щ„Щ…ШіШ§ШЎ|ЩҒЩҠ Ш§Щ„Щ„ЩҠЩ„)/,
  abbreviated: /^(Шө|Щ…|ЩҶШөЩҒ Ш§Щ„Щ„ЩҠЩ„|ШёЩҮШұШ§ЩӢ|ЩҒЩҠ Ш§Щ„ШөШЁШ§Шӯ|ШЁШ№ШҜ Ш§Щ„ШёЩҮШұ|ЩҒЩҠ Ш§Щ„Щ…ШіШ§ШЎ|ЩҒЩҠ Ш§Щ„Щ„ЩҠЩ„)/,
  wide: /^(Шө|Щ…|ЩҶШөЩҒ Ш§Щ„Щ„ЩҠЩ„|ЩҒЩҠ Ш§Щ„ШөШЁШ§Шӯ|ШёЩҮШұШ§ЩӢ|ШЁШ№ШҜ Ш§Щ„ШёЩҮШұ|ЩҒЩҠ Ш§Щ„Щ…ШіШ§ШЎ|ЩҒЩҠ Ш§Щ„Щ„ЩҠЩ„)/,
  any: /^(Шө|Щ…|ШөШЁШ§Шӯ|ШёЩҮШұ|Щ…ШіШ§ШЎ|Щ„ЩҠЩ„)/,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^Шө/,
    pm: /^Щ…/,
    midnight: /^ЩҶ/,
    noon: /^Шё/,
    morning: /^Шө/,
    afternoon: /^ШЁШ№ШҜ/,
    evening: /^Щ…/,
    night: /^Щ„/,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: function (value) {
      return parseInt(value, 10);
    },
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
