const formatRelativeLocale = {
  lastWeek: (date) => {
    const day = date.getDay();

    switch (day) {
      case 0:
        return "'РҝСҖРҫСҲР»Рө РҪРөРҙРөСҷРө Сғ' p";
      case 3:
        return "'РҝСҖРҫСҲР»Рө СҒСҖРөРҙРө Сғ' p";
      case 6:
        return "'РҝСҖРҫСҲР»Рө СҒСғРұРҫСӮРө Сғ' p";
      default:
        return "'РҝСҖРҫСҲР»Рё' EEEE 'Сғ' p";
    }
  },
  yesterday: "'СҳСғСҮРө Сғ' p",
  today: "'РҙР°РҪР°СҒ Сғ' p",
  tomorrow: "'СҒСғСӮСҖР° Сғ' p",
  nextWeek: (date) => {
    const day = date.getDay();

    switch (day) {
      case 0:
        return "'СҒР»РөРҙРөСӣРө РҪРөРҙРөСҷРө Сғ' p";
      case 3:
        return "'СҒР»РөРҙРөСӣСғ СҒСҖРөРҙСғ Сғ' p";
      case 6:
        return "'СҒР»РөРҙРөСӣСғ СҒСғРұРҫСӮСғ Сғ' p";
      default:
        return "'СҒР»РөРҙРөСӣРё' EEEE 'Сғ' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
