import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)((-|ЦҠ)?(Х«Х¶|ЦҖХӨ))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(Х”|Х„)/i,
  abbreviated: /^(Х”\.?\s?Фұ\.?|Х„\.?\s?Ф№\.?\s?Фұ\.?|Х„\.?\s?Ф№\.?|Х”\.?\s?ХҖ\.?)/i,
  wide: /^(Ц„ЦҖХ«ХҪХҝХёХҪХ«ЦҒ ХЎХјХЎХ»|ХҙХҘЦҖ Х©ХҫХЎЦҖХҜХёЦӮХ©ХөХёЦӮХ¶Х«ЦҒ ХЎХјХЎХ»|ХҙХҘЦҖ Х©ХҫХЎЦҖХҜХёЦӮХ©ХөХЎХ¶|Ц„ЦҖХ«ХҪХҝХёХҪХ«ЦҒ Х°ХҘХҝХё)/i,
};
const parseEraPatterns = {
  any: [/^Ц„/i, /^Хҙ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^Ц„[1234]/i,
  wide: /^[1234]((-|ЦҠ)?(Х«Х¶|ЦҖХӨ)) Ц„ХЎХјХёЦҖХӨ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[Х°ЦғХҙХЎЦ…ХҪХ¶ХӨ]/i,
  abbreviated: /^(Х°ХёЦӮХ¶|ЦғХҘХҝ|ХҙХЎЦҖ|ХЎХәЦҖ|ХҙХЎХө|Х°ХёЦӮХ¶|Х°ХёЦӮХ¬|Ц…ХЈХҪ|ХҪХҘХә|Х°ХёХҜ|Х¶ХёХө|ХӨХҘХҜ)/i,
  wide: /^(Х°ХёЦӮХ¶ХҫХЎЦҖ|ЦғХҘХҝЦҖХҫХЎЦҖ|ХҙХЎЦҖХҝ|ХЎХәЦҖХ«Х¬|ХҙХЎХөХ«ХҪ|Х°ХёЦӮХ¶Х«ХҪ|Х°ХёЦӮХ¬Х«ХҪ|Ц…ХЈХёХҪХҝХёХҪ|ХҪХҘХәХҝХҘХҙХўХҘЦҖ|Х°ХёХҜХҝХҘХҙХўХҘЦҖ|Х¶ХёХөХҘХҙХўХҘЦҖ|ХӨХҘХҜХҝХҘХҙХўХҘЦҖ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^Х°/i,
    /^Цғ/i,
    /^Хҙ/i,
    /^ХЎ/i,
    /^Хҙ/i,
    /^Х°/i,
    /^Х°/i,
    /^Ц…/i,
    /^ХҪ/i,
    /^Х°/i,
    /^Х¶/i,
    /^ХӨ/i,
  ],

  any: [
    /^Х°ХёЦӮ/i,
    /^Цғ/i,
    /^ХҙХЎЦҖ/i,
    /^ХЎ/i,
    /^ХҙХЎХө/i,
    /^Х°ХёЦӮХ¶/i,
    /^Х°ХёЦӮХ¬/i,
    /^Ц…/i,
    /^ХҪ/i,
    /^Х°ХёХҜ/i,
    /^Х¶/i,
    /^ХӨ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ХҘХ№Х°ХёХ·ХҜ]/i,
  short: /^(ХҜЦҖ|ХҘЦҖ|ХҘЦ„|Х№Ц„|Х°ХЈ|ХёЦӮЦҖ|Х·Хў)/i,
  abbreviated: /^(ХҜХ«ЦҖ|ХҘЦҖХҜ|ХҘЦҖЦ„|Х№ХёЦҖ|Х°Х¶ХЈ|ХёЦӮЦҖХў|Х·ХЎХў)/i,
  wide: /^(ХҜХ«ЦҖХЎХҜХ«|ХҘЦҖХҜХёЦӮХ·ХЎХўХ©Х«|ХҘЦҖХҘЦ„Х·ХЎХўХ©Х«|Х№ХёЦҖХҘЦ„Х·ХЎХўХ©Х«|Х°Х«Х¶ХЈХ·ХЎХўХ©Х«|ХёЦӮЦҖХўХЎХ©|Х·ХЎХўХЎХ©)/i,
};
const parseDayPatterns = {
  narrow: [/^ХҜ/i, /^ХҘ/i, /^ХҘ/i, /^Х№/i, /^Х°/i, /^(Хё|ХҲ)/, /^Х·/i],
  short: [/^ХҜ/i, /^ХҘЦҖ/i, /^ХҘЦ„/i, /^Х№/i, /^Х°/i, /^(Хё|ХҲ)/, /^Х·/i],
  abbreviated: [/^ХҜ/i, /^ХҘЦҖХҜ/i, /^ХҘЦҖЦ„/i, /^Х№/i, /^Х°/i, /^(Хё|ХҲ)/, /^Х·/i],

  wide: [/^ХҜ/i, /^ХҘЦҖХҜ/i, /^ХҘЦҖХҘ/i, /^Х№/i, /^Х°/i, /^(Хё|ХҲ)/, /^Х·/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([ap]|ХҜХҘХҪХЈХ·|ХҜХҘХҪЦ…ЦҖ|(ХЎХјХЎХҫХёХҝХЁ?|ЦҒХҘЦҖХҘХҜХЁ?|ХҘЦҖХҘХҜХё(ХөХЎХ¶)?|ХЈХ«Х·ХҘЦҖХЁ?))/i,
  any: /^([ap]\.?\s?m\.?|ХҜХҘХҪХЈХ«Х·ХҘЦҖ(Х«Х¶)?|ХҜХҘХҪЦ…ЦҖ(Х«Х¶)?|(ХЎХјХЎХҫХёХҝХЁ?|ЦҒХҘЦҖХҘХҜХЁ?|ХҘЦҖХҘХҜХё(ХөХЎХ¶)?|ХЈХ«Х·ХҘЦҖХЁ?))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^a/i,
    pm: /^p/i,
    midnight: /ХҜХҘХҪХЈХ«Х·ХҘЦҖ/i,
    noon: /ХҜХҘХҪЦ…ЦҖ/i,
    morning: /ХЎХјХЎХҫХёХҝ/i,
    afternoon: /ЦҒХҘЦҖХҘХҜ/i,
    evening: /ХҘЦҖХҘХҜХё/i,
    night: /ХЈХ«Х·ХҘЦҖ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "wide",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
