const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "minna en 1 sekГәnda",
    other: "minna en {{count}} sekГәndur",
  },

  xSeconds: {
    one: "1 sekГәnda",
    other: "{{count}} sekГәndur",
  },

  halfAMinute: "hГЎlf mГӯnГәta",

  lessThanXMinutes: {
    one: "minna en 1 mГӯnГәta",
    other: "minna en {{count}} mГӯnГәtur",
  },

  xMinutes: {
    one: "1 mГӯnГәta",
    other: "{{count}} mГӯnГәtur",
  },

  aboutXHours: {
    one: "u.Гҫ.b. 1 klukkustund",
    other: "u.Гҫ.b. {{count}} klukkustundir",
  },

  xHours: {
    one: "1 klukkustund",
    other: "{{count}} klukkustundir",
  },

  xDays: {
    one: "1 dagur",
    other: "{{count}} dagar",
  },

  aboutXWeeks: {
    one: "um viku",
    other: "um {{count}} vikur",
  },

  xWeeks: {
    one: "1 viku",
    other: "{{count}} vikur",
  },

  aboutXMonths: {
    one: "u.Гҫ.b. 1 mГЎnuГ°ur",
    other: "u.Гҫ.b. {{count}} mГЎnuГ°ir",
  },

  xMonths: {
    one: "1 mГЎnuГ°ur",
    other: "{{count}} mГЎnuГ°ir",
  },

  aboutXYears: {
    one: "u.Гҫ.b. 1 ГЎr",
    other: "u.Гҫ.b. {{count}} ГЎr",
  },

  xYears: {
    one: "1 ГЎr",
    other: "{{count}} ГЎr",
  },

  overXYears: {
    one: "meira en 1 ГЎr",
    other: "meira en {{count}} ГЎr",
  },

  almostXYears: {
    one: "nГҰstum 1 ГЎr",
    other: "nГҰstum {{count}} ГЎr",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", count.toString());
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "Гӯ " + result;
    } else {
      return result + " sГӯГ°an";
    }
  }

  return result;
};
