import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(th|st|nd|rd)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(ШЁ|Щғ)/i,
  wide: /^(Щ…ЩүЩҠЩ„Ш§ШҜЩүШҜЩүЩҶ ШЁЫҮШұЫҮЩҶ|Щ…ЩүЩҠЩ„Ш§ШҜЩүШҜЩүЩҶ ЩғЩүЩҠЩүЩҶ)/i,
};
const parseEraPatterns = {
  any: [/^ШЁЫҮШұЫҮЩҶ/i, /^ЩғЩүЩҠЩүЩҶ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^ЪҶ[1234]/i,
  wide: /^ЪҶШ§ШұЫ•Щғ [1234]/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  // eslint-disable-next-line no-misleading-character-class
  narrow: /^[ЩҠЩҒЩ…ШҰШ§Щ…ШҰвҖҚШҰШ§ШіЫҶЩҶШҜ]/i,
  abbreviated:
    /^(ЩҠШ§ЩҶЫӢШ§Шұ|ЩҒЫҗЫӢЩүШұШ§Щ„|Щ…Ш§ШұШӘ|ШҰШ§ЩҫШұЩүЩ„|Щ…Ш§ЩҠ|ШҰЩүЩҠЫҮЩҶ|ШҰЩүЩҠЩҲЩ„|ШҰШ§ЫӢШәЫҮШіШӘ|ШіЩүЩҶШӘЫ•ШЁЩүШұ|ШҰЫҶЩғШӘЫ•ШЁЩүШұ|ЩҶЩҲЩҠШ§ШЁЩүШұ|ШҜЩүЩғШ§ШЁЩүШұ)/i,
  wide: /^(ЩҠШ§ЩҶЫӢШ§Шұ|ЩҒЫҗЫӢЩүШұШ§Щ„|Щ…Ш§ШұШӘ|ШҰШ§ЩҫШұЩүЩ„|Щ…Ш§ЩҠ|ШҰЩүЩҠЫҮЩҶ|ШҰЩүЩҠЩҲЩ„|ШҰШ§ЫӢШәЫҮШіШӘ|ШіЩүЩҶШӘЫ•ШЁЩүШұ|ШҰЫҶЩғШӘЫ•ШЁЩүШұ|ЩҶЩҲЩҠШ§ШЁЩүШұ|ШҜЩүЩғШ§ШЁЩүШұ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^ЩҠ/i,
    /^ЩҒ/i,
    /^Щ…/i,
    /^Ш§/i,
    /^Щ…/i,
    /^ЩүвҖҚ/i,
    /^ЩүвҖҚ/i,
    /^Ш§вҖҚ/i,
    /^Ші/i,
    /^ЫҶ/i,
    /^ЩҶ/i,
    /^ШҜ/i,
  ],

  any: [
    /^ЩҠШ§ЩҶ/i,
    /^ЩҒЫҗЫӢ/i,
    /^Щ…Ш§Шұ/i,
    /^ШҰШ§Щҫ/i,
    /^Щ…Ш§ЩҠ/i,
    /^ШҰЩүЩҠЫҮЩҶ/i,
    /^ШҰЩүЩҠЩҲЩ„/i,
    /^ШҰШ§ЫӢ/i,
    /^ШіЩүЩҶ/i,
    /^ШҰЫҶЩғ/i,
    /^ЩҶЩҲЩҠ/i,
    /^ШҜЩүЩғ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ШҜШіЪҶЩҫШ¬ШҙЩҠ]/i,
  short: /^(ЩҠЫ•|ШҜЫҲ|ШіЫ•|ЪҶШ§|ЩҫЫ•|Ш¬ЫҲ|ШҙЫ•)/i,
  abbreviated: /^(ЩҠЫ•|ШҜЫҲ|ШіЫ•|ЪҶШ§|ЩҫЫ•|Ш¬ЫҲ|ШҙЫ•)/i,
  wide: /^(ЩҠЫ•ЩғШҙЫ•ЩҶШЁЫ•|ШҜЫҲШҙЫ•ЩҶШЁЫ•|ШіЫ•ЩҠШҙЫ•ЩҶШЁЫ•|ЪҶШ§ШұШҙЫ•ЩҶШЁЫ•|ЩҫЫ•ЩҠШҙЫ•ЩҶШЁЫ•|Ш¬ЫҲЩ…Ы•|ШҙЫ•ЩҶШЁЫ•)/i,
};
const parseDayPatterns = {
  narrow: [/^ЩҠ/i, /^ШҜ/i, /^Ші/i, /^ЪҶ/i, /^Щҫ/i, /^Ш¬/i, /^Шҙ/i],
  any: [/^ЩҠ/i, /^ШҜ/i, /^Ші/i, /^ЪҶ/i, /^Щҫ/i, /^Ш¬/i, /^Шҙ/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(ШҰЫ•|ЪҶ|Щғ|ЪҶ|(ШҜЫ•|ШҰЫ•ШӘЩүЪҜЫ•ЩҶ) ( ШҰЫ•вҖҚ|ЪҶЫҲШҙШӘЩүЩҶ ЩғЩүЩҠЩүЩҶ|ШҰШ§Ш®ШҙЩүЩ…|ЩғЩүЪҶЫ•))/i,
  any: /^(ШҰЫ•|ЪҶ|Щғ|ЪҶ|(ШҜЫ•|ШҰЫ•ШӘЩүЪҜЫ•ЩҶ) ( ШҰЫ•вҖҚ|ЪҶЫҲШҙШӘЩүЩҶ ЩғЩүЩҠЩүЩҶ|ШҰШ§Ш®ШҙЩүЩ…|ЩғЩүЪҶЫ•))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^ШҰЫ•/i,
    pm: /^ЪҶ/i,
    midnight: /^Щғ/i,
    noon: /^ЪҶ/i,
    morning: /ШҰЫ•ШӘЩүЪҜЫ•ЩҶ/i,
    afternoon: /ЪҶЫҲШҙШӘЩүЩҶ ЩғЩүЩҠЩүЩҶ/i,
    evening: /ШҰШ§Ш®ШҙЩүЩ…/i,
    night: /ЩғЩүЪҶЫ•/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
