import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern =
  /^(\d+)(-?(Рө|СҸ|РіР°|С–|СӢ|Р°Рө|Р°СҸ|СҸСҸ|СҲСӢ|РіС–|СҶС–|СӮСӢ|РјСӢ))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((РҙР° )?РҪ\.?\s?СҚ\.?)/i,
  abbreviated: /^((РҙР° )?РҪ\.?\s?СҚ\.?)/i,
  wide: /^(РҙР° РҪР°СҲР°Р№ СҚСҖСӢ|РҪР°СҲР°Р№ СҚСҖСӢ|РҪР°СҲР° СҚСҖР°)/i,
};
const parseEraPatterns = {
  any: [/^Рҙ/i, /^РҪ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[СӢС–]?)? РәРІ.?/i,
  wide: /^[1234](-?[СӢС–]?)? РәРІР°СҖСӮР°Р»/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[СҒР»РәРјСҮР¶РІ]/i,
  abbreviated:
    /^(СҒСӮСғРҙР·|Р»СҺСӮ|СҒР°Рә|РәСҖР°СҒ|СӮСҖ(Р°РІ)?|СҮСҚСҖРІ|Р»С–Рҝ|Р¶РҪ|РІРөСҖ|РәР°СҒСӮСҖ|Р»С–СҒСӮ|СҒСҢРҪРөР¶)\.?/i,
  wide: /^(СҒСӮСғРҙР·РөРҪ[СҢСҸ]|Р»СҺСӮ(СӢ|Р°РіР°)|СҒР°РәР°РІС–РәР°?|РәСҖР°СҒР°РІС–РәР°?|СӮСҖР°(РІРөРҪСҢ|СһРҪСҸ)|СҮСҚСҖРІРөРҪ[СҢСҸ]|Р»С–РҝРөРҪ[СҢСҸ]|Р¶РҪС–(РІРөРҪСҢ|СһРҪСҸ)|РІРөСҖР°СҒ(РөРҪСҢ|РҪСҸ)|РәР°СҒСӮСҖСӢСҮРҪС–РәР°?|Р»С–СҒСӮР°РҝР°РҙР°?|СҒСҢРҪРөР¶(Р°РҪСҢ|РҪСҸ))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^СҒ/i,
    /^Р»/i,
    /^СҒ/i,
    /^Рә/i,
    /^СӮ/i,
    /^СҮ/i,
    /^Р»/i,
    /^Р¶/i,
    /^РІ/i,
    /^Рә/i,
    /^Р»/i,
    /^СҒ/i,
  ],

  any: [
    /^СҒСӮ/i,
    /^Р»СҺ/i,
    /^СҒР°/i,
    /^РәСҖ/i,
    /^СӮСҖ/i,
    /^СҮ/i,
    /^Р»С–Рҝ/i,
    /^Р¶/i,
    /^РІ/i,
    /^РәР°/i,
    /^Р»С–СҒ/i,
    /^СҒРҪ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[РҪРҝР°СҒСҮ]/i,
  short: /^(РҪРҙ|РҪСҸ|РҝРҪ|РҝР°|Р°Сһ|Р°СӮ|СҒСҖ|СҒРө|СҮСҶ|СҮР°|РҝСӮ|РҝСҸ|СҒРұ|СҒСғ)\.?/i,
  abbreviated: /^(РҪСҸРҙР·?|РҪРҙР·|РҝРҪРҙ|РҝР°РҪ|Р°СһСӮ|СҒСҖРҙ|СҒРөСҖ|СҮСҶСҢРІ|СҮР°СҶСҢ|РҝСӮРҪ|РҝСҸСӮ|СҒСғРұ).?/i,
  wide: /^(РҪСҸРҙР·РөР»[СҸС–]|РҝР°РҪСҸРҙР·РөР»(Р°Рә|РәР°)|Р°СһСӮРҫСҖ(Р°Рә|РәР°)|СҒРөСҖР°Рҙ[Р°СӢ]|СҮР°СҶСҢРІ(РөСҖ|СҸСҖРіР°)|РҝСҸСӮРҪС–СҶ[Р°СӢ]|СҒСғРұРҫСӮ[Р°СӢ])/i,
};
const parseDayPatterns = {
  narrow: [/^РҪ/i, /^Рҝ/i, /^Р°/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^СҒ/i],
  any: [/^РҪ/i, /^Рҝ[Р°РҪ]/i, /^Р°/i, /^СҒ[РөСҖ]/i, /^СҮ/i, /^Рҝ[СҸСӮ]/i, /^СҒ[СғРұ]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([РҙРҝ]Рҝ|РҝРҫСһРҪ\.?|РҝРҫСһРҙ\.?|СҖР°РҪ\.?|РҙР·РөРҪСҢ|РҙРҪСҸ|РІРөСҮ\.?|РҪРҫСҮСӢ?)/i,
  abbreviated: /^([РҙРҝ]Рҝ|РҝРҫСһРҪ\.?|РҝРҫСһРҙ\.?|СҖР°РҪ\.?|РҙР·РөРҪСҢ|РҙРҪСҸ|РІРөСҮ\.?|РҪРҫСҮСӢ?)/i,
  wide: /^([РҙРҝ]Рҝ|РҝРҫСһРҪР°СҮ|РҝРҫСһРҙР·РөРҪСҢ|СҖР°РҪС–СҶ[Р°СӢ]|РҙР·РөРҪСҢ|РҙРҪСҸ|РІРөСҮР°СҖР°?|РҪРҫСҮСӢ?)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^РҙРҝ/i,
    pm: /^РҝРҝ/i,
    midnight: /^РҝРҫСһРҪ/i,
    noon: /^РҝРҫСһРҙ/i,
    morning: /^СҖ/i,
    afternoon: /^Рҙ[Р·РҪ]/i,
    evening: /^РІ/i,
    night: /^РҪ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
