const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "1гҒігӮҮгҒҶгҒҝгҒҫгӮ“",
    other: "{{count}}гҒігӮҮгҒҶгҒҝгҒҫгӮ“",
    oneWithSuffix: "гӮ„гҒҸ1гҒігӮҮгҒҶ",
    otherWithSuffix: "гӮ„гҒҸ{{count}}гҒігӮҮгҒҶ",
  },

  xSeconds: {
    one: "1гҒігӮҮгҒҶ",
    other: "{{count}}гҒігӮҮгҒҶ",
  },

  halfAMinute: "30гҒігӮҮгҒҶ",

  lessThanXMinutes: {
    one: "1гҒ·гӮ“гҒҝгҒҫгӮ“",
    other: "{{count}}гҒөгӮ“гҒҝгҒҫгӮ“",
    oneWithSuffix: "гӮ„гҒҸ1гҒ·гӮ“",
    otherWithSuffix: "гӮ„гҒҸ{{count}}гҒөгӮ“",
  },

  xMinutes: {
    one: "1гҒ·гӮ“",
    other: "{{count}}гҒөгӮ“",
  },

  aboutXHours: {
    one: "гӮ„гҒҸ1гҒҳгҒӢгӮ“",
    other: "гӮ„гҒҸ{{count}}гҒҳгҒӢгӮ“",
  },

  xHours: {
    one: "1гҒҳгҒӢгӮ“",
    other: "{{count}}гҒҳгҒӢгӮ“",
  },

  xDays: {
    one: "1гҒ«гҒЎ",
    other: "{{count}}гҒ«гҒЎ",
  },

  aboutXWeeks: {
    one: "гӮ„гҒҸ1гҒ—гӮ…гҒҶгҒӢгӮ“",
    other: "гӮ„гҒҸ{{count}}гҒ—гӮ…гҒҶгҒӢгӮ“",
  },

  xWeeks: {
    one: "1гҒ—гӮ…гҒҶгҒӢгӮ“",
    other: "{{count}}гҒ—гӮ…гҒҶгҒӢгӮ“",
  },

  aboutXMonths: {
    one: "гӮ„гҒҸ1гҒӢгҒ’гҒӨ",
    other: "гӮ„гҒҸ{{count}}гҒӢгҒ’гҒӨ",
  },

  xMonths: {
    one: "1гҒӢгҒ’гҒӨ",
    other: "{{count}}гҒӢгҒ’гҒӨ",
  },

  aboutXYears: {
    one: "гӮ„гҒҸ1гҒӯгӮ“",
    other: "гӮ„гҒҸ{{count}}гҒӯгӮ“",
  },

  xYears: {
    one: "1гҒӯгӮ“",
    other: "{{count}}гҒӯгӮ“",
  },

  overXYears: {
    one: "1гҒӯгӮ“гҒ„гҒҳгӮҮгҒҶ",
    other: "{{count}}гҒӯгӮ“гҒ„гҒҳгӮҮгҒҶ",
  },

  almostXYears: {
    one: "1гҒӯгӮ“гҒЎгҒӢгҒҸ",
    other: "{{count}}гҒӯгӮ“гҒЎгҒӢгҒҸ",
  },
};

export const formatDistance = (token, count, options) => {
  options = options || {};

  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    if (options.addSuffix && tokenValue.oneWithSuffix) {
      result = tokenValue.oneWithSuffix;
    } else {
      result = tokenValue.one;
    }
  } else {
    if (options.addSuffix && tokenValue.otherWithSuffix) {
      result = tokenValue.otherWithSuffix.replace("{{count}}", String(count));
    } else {
      result = tokenValue.other.replace("{{count}}", String(count));
    }
  }

  if (options.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + "гҒӮгҒЁ";
    } else {
      return result + "гҒҫгҒҲ";
    }
  }

  return result;
};
