import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(\.)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(mГ¶|ms)/i,
  abbreviated: /^(mГ¶|ms)/i,
  wide: /^(milattan Г¶nce|milattan sonra)/i,
};
const parseEraPatterns = {
  any: [/(^mГ¶|^milattan Г¶nce)/i, /(^ms|^milattan sonra)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]Г§/i,
  wide: /^((i|Д°)lk|(i|Д°)kinci|ГјГ§ГјncГј|son) Г§eyrek/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
  abbreviated: [/1Г§/i, /2Г§/i, /3Г§/i, /4Г§/i],
  wide: [
    /^(i|Д°)lk Г§eyrek/i,
    /(i|Д°)kinci Г§eyrek/i,
    /ГјГ§ГјncГј Г§eyrek/i,
    /son Г§eyrek/i,
  ],
};

const matchMonthPatterns = {
  narrow: /^[oЕҹmnhtaek]/i,
  abbreviated: /^(oca|Еҹub|mar|nis|may|haz|tem|aДҹu|eyl|eki|kas|ara)/i,
  wide: /^(ocak|Еҹubat|mart|nisan|mayДұs|haziran|temmuz|aДҹustos|eylГјl|ekim|kasДұm|aralДұk)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^o/i,
    /^Еҹ/i,
    /^m/i,
    /^n/i,
    /^m/i,
    /^h/i,
    /^t/i,
    /^a/i,
    /^e/i,
    /^e/i,
    /^k/i,
    /^a/i,
  ],

  any: [
    /^o/i,
    /^Еҹ/i,
    /^mar/i,
    /^n/i,
    /^may/i,
    /^h/i,
    /^t/i,
    /^aДҹ/i,
    /^ey/i,
    /^ek/i,
    /^k/i,
    /^ar/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[psГ§c]/i,
  short: /^(pz|pt|sa|Г§a|pe|cu|ct)/i,
  abbreviated: /^(paz|pzt|sal|Г§ar|per|cum|cts)/i,
  wide: /^(pazar(?!tesi)|pazartesi|salДұ|Г§arЕҹamba|perЕҹembe|cuma(?!rtesi)|cumartesi)/i,
};
const parseDayPatterns = {
  narrow: [/^p/i, /^p/i, /^s/i, /^Г§/i, /^p/i, /^c/i, /^c/i],
  any: [/^pz/i, /^pt/i, /^sa/i, /^Г§a/i, /^pe/i, /^cu/i, /^ct/i],
  wide: [
    /^pazar(?!tesi)/i,
    /^pazartesi/i,
    /^salДұ/i,
    /^Г§arЕҹamba/i,
    /^perЕҹembe/i,
    /^cuma(?!rtesi)/i,
    /^cumartesi/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow: /^(Г¶Г¶|Г¶s|gy|Г¶|sa|Г¶s|ak|ge)/i,
  any: /^(Г¶\.?\s?[Г¶s]\.?|Г¶Дҹleden sonra|gece yarДұsДұ|Г¶Дҹle|(sabah|Г¶Дҹ|akЕҹam|gece)(leyin))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^Г¶\.?Г¶\.?/i,
    pm: /^Г¶\.?s\.?/i,
    midnight: /^(gy|gece yarДұsДұ)/i,
    noon: /^Г¶Дҹ/i,
    morning: /^sa/i,
    afternoon: /^Г¶Дҹleden sonra/i,
    evening: /^ak/i,
    night: /^ge/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: function (value) {
      return parseInt(value, 10);
    },
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
