// Source: https://www.unicode.org/cldr/charts/32/summary/te.html

const formatRelativeLocale = {
  lastWeek: "'а°—а°Ө' eeee p", // CLDR #1384
  yesterday: "'а°Ёа°ҝа°ЁаұҚа°Ё' p", // CLDR #1393
  today: "'а°Ҳ а°°аұӢа°ңаұҒ' p", // CLDR #1394
  tomorrow: "'а°°аұҮа°ӘаұҒ' p", // CLDR #1395
  nextWeek: "'а°Өа°ҰаұҒа°Әа°°а°ҝ' eeee p", // CLDR #1386
  other: "P",
};

export const formatRelative = (token, _date, _baseDate, _options) =>
  formatRelativeLocale[token];
