const formatRelativeLocale = {
  lastWeek: (date) => {
    switch (date.getDay()) {
      case 6: //ОЈО¬ОІОІОұП„Оҝ
        return "'П„Оҝ ПҖПҒОҝО·ОіОҝПҚОјОөОҪОҝ' eeee 'ПғП„О№ПӮ' p";
      default:
        return "'П„О·ОҪ ПҖПҒОҝО·ОіОҝПҚОјОөОҪО·' eeee 'ПғП„О№ПӮ' p";
    }
  },
  yesterday: "'ПҮОёОөПӮ ПғП„О№ПӮ' p",
  today: "'ПғО®ОјОөПҒОұ ПғП„О№ПӮ' p",
  tomorrow: "'ОұПҚПҒО№Оҝ ПғП„О№ПӮ' p",
  nextWeek: "eeee 'ПғП„О№ПӮ' p",
  other: "P",
};

export const formatRelative = (token, date) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") return format(date);

  return format;
};
