const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "1мҙҲ лҜёл§Ң",
    other: "{{count}}мҙҲ лҜёл§Ң",
  },

  xSeconds: {
    one: "1мҙҲ",
    other: "{{count}}мҙҲ",
  },

  halfAMinute: "30мҙҲ",

  lessThanXMinutes: {
    one: "1л¶„ лҜёл§Ң",
    other: "{{count}}л¶„ лҜёл§Ң",
  },

  xMinutes: {
    one: "1л¶„",
    other: "{{count}}л¶„",
  },

  aboutXHours: {
    one: "м•Ҫ 1мӢңк°„",
    other: "м•Ҫ {{count}}мӢңк°„",
  },

  xHours: {
    one: "1мӢңк°„",
    other: "{{count}}мӢңк°„",
  },

  xDays: {
    one: "1мқј",
    other: "{{count}}мқј",
  },

  aboutXWeeks: {
    one: "м•Ҫ 1мЈј",
    other: "м•Ҫ {{count}}мЈј",
  },

  xWeeks: {
    one: "1мЈј",
    other: "{{count}}мЈј",
  },

  aboutXMonths: {
    one: "м•Ҫ 1к°ңмӣ”",
    other: "м•Ҫ {{count}}к°ңмӣ”",
  },

  xMonths: {
    one: "1к°ңмӣ”",
    other: "{{count}}к°ңмӣ”",
  },

  aboutXYears: {
    one: "м•Ҫ 1л…„",
    other: "м•Ҫ {{count}}л…„",
  },

  xYears: {
    one: "1л…„",
    other: "{{count}}л…„",
  },

  overXYears: {
    one: "1л…„ мқҙмғҒ",
    other: "{{count}}л…„ мқҙмғҒ",
  },

  almostXYears: {
    one: "кұ°мқҳ 1л…„",
    other: "кұ°мқҳ {{count}}л…„",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", count.toString());
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + " нӣ„";
    } else {
      return result + " м „";
    }
  }

  return result;
};
