import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(з¬¬\s*)?\d+(ж—Ҙ|жҷӮ|еҲҶ|з§’)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(еүҚ)/i,
  abbreviated: /^(еүҚ)/i,
  wide: /^(е…¬е…ғеүҚ|е…¬е…ғ)/i,
};
const parseEraPatterns = {
  any: [/^(еүҚ)/i, /^(е…¬е…ғ)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^з¬¬[дёҖдәҢдёүеӣӣ]еҲ»/i,
  wide: /^з¬¬[дёҖдәҢдёүеӣӣ]еҲ»йҗҳ/i,
};
const parseQuarterPatterns = {
  any: [/(1|дёҖ)/i, /(2|дәҢ)/i, /(3|дёү)/i, /(4|еӣӣ)/i],
};

const matchMonthPatterns = {
  narrow: /^(дёҖ|дәҢ|дёү|еӣӣ|дә”|е…ӯ|дёғ|е…«|д№қ|еҚҒ[дәҢдёҖ])/i,
  abbreviated: /^(дёҖ|дәҢ|дёү|еӣӣ|дә”|е…ӯ|дёғ|е…«|д№қ|еҚҒ[дәҢдёҖ]|\d|1[12])жңҲ/i,
  wide: /^(дёҖ|дәҢ|дёү|еӣӣ|дә”|е…ӯ|дёғ|е…«|д№қ|еҚҒ[дәҢдёҖ])жңҲ/i,
};
const parseMonthPatterns = {
  narrow: [
    /^дёҖ/i,
    /^дәҢ/i,
    /^дёү/i,
    /^еӣӣ/i,
    /^дә”/i,
    /^е…ӯ/i,
    /^дёғ/i,
    /^е…«/i,
    /^д№қ/i,
    /^еҚҒ(?!(дёҖ|дәҢ))/i,
    /^еҚҒдёҖ/i,
    /^еҚҒдәҢ/i,
  ],

  any: [
    /^дёҖ|1/i,
    /^дәҢ|2/i,
    /^дёү|3/i,
    /^еӣӣ|4/i,
    /^дә”|5/i,
    /^е…ӯ|6/i,
    /^дёғ|7/i,
    /^е…«|8/i,
    /^д№қ|9/i,
    /^еҚҒ(?!(дёҖ|дәҢ))|10/i,
    /^еҚҒдёҖ|11/i,
    /^еҚҒдәҢ|12/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[дёҖдәҢдёүеӣӣдә”е…ӯж—Ҙ]/i,
  short: /^[дёҖдәҢдёүеӣӣдә”е…ӯж—Ҙ]/i,
  abbreviated: /^йҖұ[дёҖдәҢдёүеӣӣдә”е…ӯж—Ҙ]/i,
  wide: /^жҳҹжңҹ[дёҖдәҢдёүеӣӣдә”е…ӯж—Ҙ]/i,
};
const parseDayPatterns = {
  any: [/ж—Ҙ/i, /дёҖ/i, /дәҢ/i, /дёү/i, /еӣӣ/i, /дә”/i, /е…ӯ/i],
};

const matchDayPeriodPatterns = {
  any: /^(дёҠеҚҲ?|дёӢеҚҲ?|еҚҲеӨң|[дёӯжӯЈ]еҚҲ|ж—©дёҠ?|дёӢеҚҲ|жҷҡдёҠ?|еҮҢжҷЁ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^дёҠеҚҲ?/i,
    pm: /^дёӢеҚҲ?/i,
    midnight: /^еҚҲеӨң/i,
    noon: /^[дёӯжӯЈ]еҚҲ/i,
    morning: /^ж—©дёҠ/i,
    afternoon: /^дёӢеҚҲ/i,
    evening: /^жҷҡдёҠ?/i,
    night: /^еҮҢжҷЁ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
