const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "СҒРөРәСғРҪРҙ С…ТҜСҖСҚС…РіТҜР№",
    other: "{{count}} СҒРөРәСғРҪРҙ С…ТҜСҖСҚС…РіТҜР№",
  },

  xSeconds: {
    one: "1 СҒРөРәСғРҪРҙ",
    other: "{{count}} СҒРөРәСғРҪРҙ",
  },

  halfAMinute: "С…Р°РіР°СҒ РјРёРҪСғСӮ",

  lessThanXMinutes: {
    one: "РјРёРҪСғСӮ С…ТҜСҖСҚС…РіТҜР№",
    other: "{{count}} РјРёРҪСғСӮ С…ТҜСҖСҚС…РіТҜР№",
  },

  xMinutes: {
    one: "1 РјРёРҪСғСӮ",
    other: "{{count}} РјРёРҪСғСӮ",
  },

  aboutXHours: {
    one: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ 1 СҶР°Рі",
    other: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ {{count}} СҶР°Рі",
  },

  xHours: {
    one: "1 СҶР°Рі",
    other: "{{count}} СҶР°Рі",
  },

  xDays: {
    one: "1 У©РҙУ©СҖ",
    other: "{{count}} У©РҙУ©СҖ",
  },

  aboutXWeeks: {
    one: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ 1 РҙРҫР»РҫРҫ С…РҫРҪРҫРі",
    other: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ {{count}} РҙРҫР»РҫРҫ С…РҫРҪРҫРі",
  },

  xWeeks: {
    one: "1 РҙРҫР»РҫРҫ С…РҫРҪРҫРі",
    other: "{{count}} РҙРҫР»РҫРҫ С…РҫРҪРҫРі",
  },

  aboutXMonths: {
    one: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ 1 СҒР°СҖ",
    other: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ {{count}} СҒР°СҖ",
  },

  xMonths: {
    one: "1 СҒР°СҖ",
    other: "{{count}} СҒР°СҖ",
  },

  aboutXYears: {
    one: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ 1 Р¶РёР»",
    other: "РҫР№СҖРҫР»СҶРҫРҫРіРҫРҫСҖ {{count}} Р¶РёР»",
  },

  xYears: {
    one: "1 Р¶РёР»",
    other: "{{count}} Р¶РёР»",
  },

  overXYears: {
    one: "1 Р¶РёР» РіР°СҖР°РҪ",
    other: "{{count}} Р¶РёР» РіР°СҖР°РҪ",
  },

  almostXYears: {
    one: "РұР°СҖР°Рі 1 Р¶РёР»",
    other: "РұР°СҖР°Рі {{count}} Р¶РёР»",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    /**
     * Append genitive case
     */
    const words = result.split(" ");
    const lastword = words.pop();
    result = words.join(" ");
    switch (lastword) {
      case "СҒРөРәСғРҪРҙ":
        result += " СҒРөРәСғРҪРҙРёР№РҪ";
        break;
      case "РјРёРҪСғСӮ":
        result += " РјРёРҪСғСӮСӢРҪ";
        break;
      case "СҶР°Рі":
        result += " СҶР°РіРёР№РҪ";
        break;
      case "У©РҙУ©СҖ":
        result += " У©РҙСҖРёР№РҪ";
        break;
      case "СҒР°СҖ":
        result += " СҒР°СҖСӢРҪ";
        break;
      case "Р¶РёР»":
        result += " Р¶РёР»РёР№РҪ";
        break;
      case "С…РҫРҪРҫРі":
        result += " С…РҫРҪРҫРіРёР№РҪ";
        break;
      case "РіР°СҖР°РҪ":
        result += " РіР°СҖР°РҪСӢ";
        break;
      case "С…ТҜСҖСҚС…РіТҜР№":
        result += " С…ТҜСҖСҚС…РіТҜР№ С…СғРіР°СҶР°Р°РҪСӢ";
        break;
      default:
        result += lastword + "-РҪ";
    }

    if (options.comparison && options.comparison > 0) {
      return result + " РҙР°СҖР°Р°";
    } else {
      return result + " У©РјРҪУ©";
    }
  }

  return result;
};
