import { isSameWeek } from "../../../isSameWeek.js";
import { toDate } from "../../../toDate.js";

// Adapted from the `ru` translation

const weekdays = [
  "РҪРөРҙРөР»СҸ",
  "РҝРҫРҪРөРҙРөР»РҪРёРә",
  "РІСӮРҫСҖРҪРёРә",
  "СҒСҖСҸРҙР°",
  "СҮРөСӮРІСҠСҖСӮСҠРә",
  "РҝРөСӮСҠРә",
  "СҒСҠРұРҫСӮР°",
];

function lastWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'РјРёРҪР°Р»Р°СӮР° " + weekday + " РІ' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'РјРёРҪР°Р»РёСҸ " + weekday + " РІ' p";
  }
}

function thisWeek(day) {
  const weekday = weekdays[day];

  if (day === 2 /* Tue */) {
    return "'РІСҠРІ " + weekday + " РІ' p";
  } else {
    return "'РІ " + weekday + " РІ' p";
  }
}

function nextWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'СҒР»РөРҙРІР°СүР°СӮР° " + weekday + " РІ' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'СҒР»РөРҙРІР°СүРёСҸ " + weekday + " РІ' p";
  }
}

const lastWeekFormatToken = (dirtyDate, baseDate, options) => {
  const date = toDate(dirtyDate);
  const day = date.getDay();
  if (isSameWeek(date, baseDate, options)) {
    return thisWeek(day);
  } else {
    return lastWeek(day);
  }
};

const nextWeekFormatToken = (dirtyDate, baseDate, options) => {
  const date = toDate(dirtyDate);
  const day = date.getDay();
  if (isSameWeek(date, baseDate, options)) {
    return thisWeek(day);
  } else {
    return nextWeek(day);
  }
};

const formatRelativeLocale = {
  lastWeek: lastWeekFormatToken,
  yesterday: "'РІСҮРөСҖР° РІ' p",
  today: "'РҙРҪРөСҒ РІ' p",
  tomorrow: "'СғСӮСҖРө РІ' p",
  nextWeek: nextWeekFormatToken,
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
