const formatRelativeLocale = {
  lastWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'proЕЎle nedelje u' p";
      case 3:
        return "'proЕЎle srede u' p";
      case 6:
        return "'proЕЎle subote u' p";
      default:
        return "'proЕЎli' EEEE 'u' p";
    }
  },
  yesterday: "'juДҚe u' p",
  today: "'danas u' p",
  tomorrow: "'sutra u' p",
  nextWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'sledeДҮe nedelje u' p";
      case 3:
        return "'sledeДҮu sredu u' p";
      case 6:
        return "'sledeДҮu subotu u' p";
      default:
        return "'sledeДҮi' EEEE 'u' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
