import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern =
  /^(\d+)(-?[РІСҖРјСӮ][Р°Рё]|-?СӮ?(РөРҪ|РҪР°)|-?(РөРІ|РөРІР°))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((РҝСҖ)?РҪ\.?\s?Рө\.?)/i,
  abbreviated: /^((РҝСҖ)?РҪ\.?\s?Рө\.?)/i,
  wide: /^(РҝСҖРөРҙРё РҪРҫРІР°СӮР° РөСҖР°|РҪРҫРІР°СӮР° РөСҖР°|РҪРҫРІР° РөСҖР°)/i,
};
const parseEraPatterns = {
  any: [/^Рҝ/i, /^РҪ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[РІСҖСӮ]?o?)? СӮСҖРёРјРөСҒ.?/i,
  wide: /^[1234](-?[РІСҖСӮ]?Рҫ?)? СӮСҖРёРјРөСҒРөСҮРёРө/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchDayPatterns = {
  narrow: /^[РҪРҝРІСҒСҮ]/i,
  short: /^(РҪРҙ|РҝРҪ|РІСӮ|СҒСҖ|СҮСӮ|РҝСӮ|СҒРұ)/i,
  abbreviated: /^(РҪРөРҙ|РҝРҫРҪ|РІСӮРҫ|СҒСҖСҸ|СҮРөСӮ|РҝРөСӮ|СҒСҠРұ)/i,
  wide: /^(РҪРөРҙРөР»СҸ|РҝРҫРҪРөРҙРөР»РҪРёРә|РІСӮРҫСҖРҪРёРә|СҒСҖСҸРҙР°|СҮРөСӮРІСҠСҖСӮСҠРә|РҝРөСӮСҠРә|СҒСҠРұРҫСӮР°)/i,
};

const parseDayPatterns = {
  narrow: [/^РҪ/i, /^Рҝ/i, /^РІ/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^СҒ/i],
  any: [/^РҪ[РөРҙ]/i, /^Рҝ[РҫРҪ]/i, /^РІСӮ/i, /^СҒСҖ/i, /^СҮ[РөСӮ]/i, /^Рҝ[РөСӮ]/i, /^СҒ[СҠРұ]/i],
};

const matchMonthPatterns = {
  abbreviated: /^(СҸРҪСғ|С„РөРІ|РјР°СҖ|Р°РҝСҖ|РјР°Р№|СҺРҪРё|СҺР»Рё|Р°РІРі|СҒРөРҝ|РҫРәСӮ|РҪРҫРө|РҙРөРә)/i,
  wide: /^(СҸРҪСғР°СҖРё|С„РөРІСҖСғР°СҖРё|РјР°СҖСӮ|Р°РҝСҖРёР»|РјР°Р№|СҺРҪРё|СҺР»Рё|Р°РІРіСғСҒСӮ|СҒРөРҝСӮРөРјРІСҖРё|РҫРәСӮРҫРјРІСҖРё|РҪРҫРөРјРІСҖРё|РҙРөРәРөРјРІСҖРё)/i,
};

const parseMonthPatterns = {
  any: [
    /^СҸ/i,
    /^С„/i,
    /^РјР°СҖ/i,
    /^Р°Рҝ/i,
    /^РјР°Р№/i,
    /^СҺРҪ/i,
    /^СҺР»/i,
    /^Р°РІ/i,
    /^СҒРө/i,
    /^РҫРәСӮ/i,
    /^РҪРҫ/i,
    /^РҙРө/i,
  ],
};

const matchDayPeriodPatterns = {
  any: /^(РҝСҖРөРҙРё Рҫ|СҒР»РөРҙ Рҫ|РІ РҝРҫ|РҪР° Рҫ|РҝСҖРөР·|РІРөСҮ|СҒСғСӮ|СҒР»РөРҙРҫ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^РҝСҖРөРҙРё Рҫ/i,
    pm: /^СҒР»РөРҙ Рҫ/i,
    midnight: /^РІ РҝРҫР»/i,
    noon: /^РҪР° РҫРұ/i,
    morning: /^СҒСғСӮ/i,
    afternoon: /^СҒР»РөРҙРҫ/i,
    evening: /^РІРөСҮ/i,
    night: /^РҝСҖРөР· РҪ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
