import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(аҰ®|а§ҹ|аҰ°а§ҚаҰҘ|аҰ·а§ҚаҰ |аҰ¶а§Ү|аҰҮ|аҰӨаҰ®)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(аҰ–а§ҚаҰ°аҰҝаҰғаҰӘа§ӮаҰғ|аҰ–а§ҚаҰ°аҰҝаҰғ)/i,
  abbreviated: /^(аҰ–а§ҚаҰ°аҰҝаҰғаҰӘа§ӮаҰ°а§ҚаҰ¬|аҰ–а§ҚаҰ°аҰҝаҰғ)/i,
  wide: /^(аҰ–а§ҚаҰ°аҰҝаҰёа§ҚаҰҹаҰӘа§ӮаҰ°а§ҚаҰ¬|аҰ–а§ҚаҰ°аҰҝаҰёа§ҚаҰҹаҰҫаҰ¬а§ҚаҰҰ)/i,
};
const parseEraPatterns = {
  narrow: [/^аҰ–а§ҚаҰ°аҰҝаҰғаҰӘа§ӮаҰғ/i, /^аҰ–а§ҚаҰ°аҰҝаҰғ/i],
  abbreviated: [/^аҰ–а§ҚаҰ°аҰҝаҰғаҰӘа§ӮаҰ°а§ҚаҰ¬/i, /^аҰ–а§ҚаҰ°аҰҝаҰғ/i],
  wide: [/^аҰ–а§ҚаҰ°аҰҝаҰёа§ҚаҰҹаҰӘа§ӮаҰ°а§ҚаҰ¬/i, /^аҰ–а§ҚаҰ°аҰҝаҰёа§ҚаҰҹаҰҫаҰ¬а§ҚаҰҰ/i],
};

const matchQuarterPatterns = {
  narrow: /^[а§§а§Ёа§©а§Ә]/i,
  abbreviated: /^[а§§а§Ёа§©а§Ә]аҰӨа§ҚаҰ°а§Ҳ/i,
  wide: /^[а§§а§Ёа§©а§Ә](аҰ®|а§ҹ|аҰ°а§ҚаҰҘ)? аҰӨа§ҚаҰ°а§ҲаҰ®аҰҫаҰёаҰҝаҰ•/i,
};
const parseQuarterPatterns = {
  any: [/а§§/i, /а§Ё/i, /а§©/i, /а§Ә/i],
};

const matchMonthPatterns = {
  narrow:
    /^(аҰңаҰҫаҰЁа§Ғ|аҰ«а§ҮаҰ¬а§ҚаҰ°а§Ғ|аҰ®аҰҫаҰ°а§ҚаҰҡ|аҰҸаҰӘа§ҚаҰ°аҰҝаҰІ|аҰ®а§Ү|аҰңа§ҒаҰЁ|аҰңа§ҒаҰІаҰҫаҰҮ|аҰҶаҰ—аҰёа§ҚаҰҹ|аҰёа§ҮаҰӘа§ҚаҰҹ|аҰ…аҰ•а§ҚаҰҹа§Ӣ|аҰЁаҰӯа§Ү|аҰЎаҰҝаҰёа§Ү)/i,
  abbreviated:
    /^(аҰңаҰҫаҰЁа§Ғ|аҰ«а§ҮаҰ¬а§ҚаҰ°а§Ғ|аҰ®аҰҫаҰ°а§ҚаҰҡ|аҰҸаҰӘа§ҚаҰ°аҰҝаҰІ|аҰ®а§Ү|аҰңа§ҒаҰЁ|аҰңа§ҒаҰІаҰҫаҰҮ|аҰҶаҰ—аҰёа§ҚаҰҹ|аҰёа§ҮаҰӘа§ҚаҰҹ|аҰ…аҰ•а§ҚаҰҹа§Ӣ|аҰЁаҰӯа§Ү|аҰЎаҰҝаҰёа§Ү)/i,
  wide: /^(аҰңаҰҫаҰЁа§Ға§ҹаҰҫаҰ°аҰҝ|аҰ«а§ҮаҰ¬а§ҚаҰ°а§Ға§ҹаҰҫаҰ°аҰҝ|аҰ®аҰҫаҰ°а§ҚаҰҡ|аҰҸаҰӘа§ҚаҰ°аҰҝаҰІ|аҰ®а§Ү|аҰңа§ҒаҰЁ|аҰңа§ҒаҰІаҰҫаҰҮ|аҰҶаҰ—аҰёа§ҚаҰҹ|аҰёа§ҮаҰӘа§ҚаҰҹа§ҮаҰ®а§ҚаҰ¬аҰ°|аҰ…аҰ•а§ҚаҰҹа§ӢаҰ¬аҰ°|аҰЁаҰӯа§ҮаҰ®а§ҚаҰ¬аҰ°|аҰЎаҰҝаҰёа§ҮаҰ®а§ҚаҰ¬аҰ°)/i,
};
const parseMonthPatterns = {
  any: [
    /^аҰңаҰҫаҰЁа§Ғ/i,
    /^аҰ«а§ҮаҰ¬а§ҚаҰ°а§Ғ/i,
    /^аҰ®аҰҫаҰ°а§ҚаҰҡ/i,
    /^аҰҸаҰӘа§ҚаҰ°аҰҝаҰІ/i,
    /^аҰ®а§Ү/i,
    /^аҰңа§ҒаҰЁ/i,
    /^аҰңа§ҒаҰІаҰҫаҰҮ/i,
    /^аҰҶаҰ—аҰёа§ҚаҰҹ/i,
    /^аҰёа§ҮаҰӘа§ҚаҰҹ/i,
    /^аҰ…аҰ•а§ҚаҰҹа§Ӣ/i,
    /^аҰЁаҰӯа§Ү/i,
    /^аҰЎаҰҝаҰёа§Ү/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(аҰ°|аҰёа§Ӣ|аҰ®|аҰ¬а§Ғ|аҰ¬а§ғ|аҰ¶а§Ғ|аҰ¶)+/i,
  short: /^(аҰ°аҰ¬аҰҝ|аҰёа§ӢаҰ®|аҰ®аҰҷа§ҚаҰ—аҰІ|аҰ¬а§ҒаҰ§|аҰ¬а§ғаҰ№|аҰ¶а§ҒаҰ•а§ҚаҰ°|аҰ¶аҰЁаҰҝ)+/i,
  abbreviated: /^(аҰ°аҰ¬аҰҝ|аҰёа§ӢаҰ®|аҰ®аҰҷа§ҚаҰ—аҰІ|аҰ¬а§ҒаҰ§|аҰ¬а§ғаҰ№|аҰ¶а§ҒаҰ•а§ҚаҰ°|аҰ¶аҰЁаҰҝ)+/i,
  wide: /^(аҰ°аҰ¬аҰҝаҰ¬аҰҫаҰ°|аҰёа§ӢаҰ®аҰ¬аҰҫаҰ°|аҰ®аҰҷа§ҚаҰ—аҰІаҰ¬аҰҫаҰ°|аҰ¬а§ҒаҰ§аҰ¬аҰҫаҰ°|аҰ¬а§ғаҰ№аҰёа§ҚаҰӘаҰӨаҰҝаҰ¬аҰҫаҰ° |аҰ¶а§ҒаҰ•а§ҚаҰ°аҰ¬аҰҫаҰ°|аҰ¶аҰЁаҰҝаҰ¬аҰҫаҰ°)+/i,
};
const parseDayPatterns = {
  narrow: [/^аҰ°/i, /^аҰёа§Ӣ/i, /^аҰ®/i, /^аҰ¬а§Ғ/i, /^аҰ¬а§ғ/i, /^аҰ¶а§Ғ/i, /^аҰ¶/i],
  short: [/^аҰ°аҰ¬аҰҝ/i, /^аҰёа§ӢаҰ®/i, /^аҰ®аҰҷа§ҚаҰ—аҰІ/i, /^аҰ¬а§ҒаҰ§/i, /^аҰ¬а§ғаҰ№/i, /^аҰ¶а§ҒаҰ•а§ҚаҰ°/i, /^аҰ¶аҰЁаҰҝ/i],

  abbreviated: [
    /^аҰ°аҰ¬аҰҝ/i,
    /^аҰёа§ӢаҰ®/i,
    /^аҰ®аҰҷа§ҚаҰ—аҰІ/i,
    /^аҰ¬а§ҒаҰ§/i,
    /^аҰ¬а§ғаҰ№/i,
    /^аҰ¶а§ҒаҰ•а§ҚаҰ°/i,
    /^аҰ¶аҰЁаҰҝ/i,
  ],

  wide: [
    /^аҰ°аҰ¬аҰҝаҰ¬аҰҫаҰ°/i,
    /^аҰёа§ӢаҰ®аҰ¬аҰҫаҰ°/i,
    /^аҰ®аҰҷа§ҚаҰ—аҰІаҰ¬аҰҫаҰ°/i,
    /^аҰ¬а§ҒаҰ§аҰ¬аҰҫаҰ°/i,
    /^аҰ¬а§ғаҰ№аҰёа§ҚаҰӘаҰӨаҰҝаҰ¬аҰҫаҰ° /i,
    /^аҰ¶а§ҒаҰ•а§ҚаҰ°аҰ¬аҰҫаҰ°/i,
    /^аҰ¶аҰЁаҰҝаҰ¬аҰҫаҰ°/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow: /^(аҰӘа§Ӯ|аҰ…аҰӘ|аҰ®аҰ§а§ҚаҰҜаҰ°аҰҫаҰӨ|аҰ®аҰ§а§ҚаҰҜаҰҫаҰ№а§ҚаҰЁ|аҰёаҰ•аҰҫаҰІ|аҰ¬аҰҝаҰ•аҰҫаҰІ|аҰёаҰЁа§ҚаҰ§а§ҚаҰҜаҰҫ|аҰ°аҰҫаҰӨ)/i,
  abbreviated: /^(аҰӘа§ӮаҰ°а§ҚаҰ¬аҰҫаҰ№а§ҚаҰЁ|аҰ…аҰӘаҰ°аҰҫаҰ№а§ҚаҰЁ|аҰ®аҰ§а§ҚаҰҜаҰ°аҰҫаҰӨ|аҰ®аҰ§а§ҚаҰҜаҰҫаҰ№а§ҚаҰЁ|аҰёаҰ•аҰҫаҰІ|аҰ¬аҰҝаҰ•аҰҫаҰІ|аҰёаҰЁа§ҚаҰ§а§ҚаҰҜаҰҫ|аҰ°аҰҫаҰӨ)/i,
  wide: /^(аҰӘа§ӮаҰ°а§ҚаҰ¬аҰҫаҰ№а§ҚаҰЁ|аҰ…аҰӘаҰ°аҰҫаҰ№а§ҚаҰЁ|аҰ®аҰ§а§ҚаҰҜаҰ°аҰҫаҰӨ|аҰ®аҰ§а§ҚаҰҜаҰҫаҰ№а§ҚаҰЁ|аҰёаҰ•аҰҫаҰІ|аҰ¬аҰҝаҰ•аҰҫаҰІ|аҰёаҰЁа§ҚаҰ§а§ҚаҰҜаҰҫ|аҰ°аҰҫаҰӨ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^аҰӘа§Ӯ/i,
    pm: /^аҰ…аҰӘ/i,
    midnight: /^аҰ®аҰ§а§ҚаҰҜаҰ°аҰҫаҰӨ/i,
    noon: /^аҰ®аҰ§а§ҚаҰҜаҰҫаҰ№а§ҚаҰЁ/i,
    morning: /аҰёаҰ•аҰҫаҰІ/i,
    afternoon: /аҰ¬аҰҝаҰ•аҰҫаҰІ/i,
    evening: /аҰёаҰЁа§ҚаҰ§а§ҚаҰҜаҰҫ/i,
    night: /аҰ°аҰҫаҰӨ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "wide",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "wide",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
