import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(аІЁаіҮ|аІЁаіҶ)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(аІ•аіҚаІ°аІҝ.аІӘаіӮ|аІ•аіҚаІ°аІҝ.аІ¶)/i,
  abbreviated: /^(аІ•аіҚаІ°аІҝ\.?\s?аІӘаіӮ\.?|аІ•аіҚаІ°аІҝ\.?\s?аІ¶\.?|аІӘаіҚаІ°\.?\s?аІ¶\.?)/i,
  wide: /^(аІ•аіҚаІ°аІҝаІёаіҚаІӨ аІӘаіӮаІ°аіҚаІө|аІ•аіҚаІ°аІҝаІёаіҚаІӨ аІ¶аІ•|аІӘаіҚаІ°аІёаІ•аіҚаІӨ аІ¶аІ•)/i,
};
const parseEraPatterns = {
  any: [/^аІӘаіӮ/i, /^(аІ¶|аІӘаіҚаІ°)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^аІӨаіҚаІ°аіҲ[1234]|аІӨаіҚаІ°аіҲ [1234]| [1234]аІӨаіҚаІ°аіҲ/i,
  wide: /^[1234](аІЁаіҮ)? аІӨаіҚаІ°аіҲаІ®аІҫаІёаІҝаІ•/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(аІңаіӮ|аІңаіҒ|аІң|аІ«аіҶ|аІ®аІҫ|аІҸ|аІ®аіҮ|аІҶ|аІёаіҶ|аІ…|аІЁ|аІЎаІҝ)/i,
  abbreviated:
    /^(аІңаІЁ|аІ«аіҶаІ¬аіҚаІ°|аІ®аІҫаІ°аіҚаІҡаіҚ|аІҸаІӘаіҚаІ°аІҝ|аІ®аіҮ|аІңаіӮаІЁаіҚ|аІңаіҒаІІаіҲ|аІҶаІ—|аІёаіҶаІӘаіҚаІҹаіҶаІӮ|аІ…аІ•аіҚаІҹаіӢ|аІЁаІөаіҶаІӮ|аІЎаІҝаІёаіҶаІӮ)/i,
  wide: /^(аІңаІЁаІөаІ°аІҝ|аІ«аіҶаІ¬аіҚаІ°аІөаІ°аІҝ|аІ®аІҫаІ°аіҚаІҡаіҚ|аІҸаІӘаіҚаІ°аІҝаІІаіҚ|аІ®аіҮ|аІңаіӮаІЁаіҚ|аІңаіҒаІІаіҲ|аІҶаІ—аІёаіҚаІҹаіҚ|аІёаіҶаІӘаіҚаІҹаіҶаІӮаІ¬аІ°аіҚ|аІ…аІ•аіҚаІҹаіӢаІ¬аІ°аіҚ|аІЁаІөаіҶаІӮаІ¬аІ°аіҚ|аІЎаІҝаІёаіҶаІӮаІ¬аІ°аіҚ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^аІң$/i,
    /^аІ«аіҶ/i,
    /^аІ®аІҫ/i,
    /^аІҸ/i,
    /^аІ®аіҮ/i,
    /^аІңаіӮ/i,
    /^аІңаіҒ$/i,
    /^аІҶ/i,
    /^аІёаіҶ/i,
    /^аІ…/i,
    /^аІЁ/i,
    /^аІЎаІҝ/i,
  ],

  any: [
    /^аІңаІЁ/i,
    /^аІ«аіҶ/i,
    /^аІ®аІҫ/i,
    /^аІҸ/i,
    /^аІ®аіҮ/i,
    /^аІңаіӮаІЁаіҚ/i,
    /^аІңаіҒаІІаіҲ/i,
    /^аІҶ/i,
    /^аІёаіҶ/i,
    /^аІ…/i,
    /^аІЁ/i,
    /^аІЎаІҝ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(аІӯаІҫ|аІёаіӢ|аІ®|аІ¬аіҒ|аІ—аіҒ|аІ¶аіҒ|аІ¶)/i,
  short: /^(аІӯаІҫаІЁаіҒ|аІёаіӢаІ®|аІ®аІӮаІ—аІі|аІ¬аіҒаІ§|аІ—аіҒаІ°аіҒ|аІ¶аіҒаІ•аіҚаІ°|аІ¶аІЁаІҝ)/i,
  abbreviated: /^(аІӯаІҫаІЁаіҒ|аІёаіӢаІ®|аІ®аІӮаІ—аІі|аІ¬аіҒаІ§|аІ—аіҒаІ°аіҒ|аІ¶аіҒаІ•аіҚаІ°|аІ¶аІЁаІҝ)/i,
  wide: /^(аІӯаІҫаІЁаіҒаІөаІҫаІ°|аІёаіӢаІ®аІөаІҫаІ°|аІ®аІӮаІ—аІіаІөаІҫаІ°|аІ¬аіҒаІ§аІөаІҫаІ°|аІ—аіҒаІ°аіҒаІөаІҫаІ°|аІ¶аіҒаІ•аіҚаІ°аІөаІҫаІ°|аІ¶аІЁаІҝаІөаІҫаІ°)/i,
};
const parseDayPatterns = {
  narrow: [/^аІӯаІҫ/i, /^аІёаіӢ/i, /^аІ®/i, /^аІ¬аіҒ/i, /^аІ—аіҒ/i, /^аІ¶аіҒ/i, /^аІ¶/i],
  any: [/^аІӯаІҫ/i, /^аІёаіӢ/i, /^аІ®/i, /^аІ¬аіҒ/i, /^аІ—аіҒ/i, /^аІ¶аіҒ/i, /^аІ¶/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(аІӘаіӮ|аІ…|аІ®аІ§аіҚаІҜаІ°аІҫаІӨаіҚаІ°аІҝ|аІ®аІ§аіҚаІҜаІҫаІЁаіҚаІ№|аІ¬аіҶаІіаІ—аіҚаІ—аіҶ|аІёаІӮаІңаіҶ|аІ°аІҫаІӨаіҚаІ°аІҝ)/i,
  any: /^(аІӘаіӮаІ°аіҚаІөаІҫаІ№аіҚаІЁ|аІ…аІӘаІ°аІҫаІ№аіҚаІЁ|аІ®аІ§аіҚаІҜаІ°аІҫаІӨаіҚаІ°аІҝ|аІ®аІ§аіҚаІҜаІҫаІЁаіҚаІ№|аІ¬аіҶаІіаІ—аіҚаІ—аіҶ|аІёаІӮаІңаіҶ|аІ°аІҫаІӨаіҚаІ°аІҝ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^аІӘаіӮ/i,
    pm: /^аІ…/i,
    midnight: /аІ®аІ§аіҚаІҜаІ°аІҫаІӨаіҚаІ°аІҝ/i,
    noon: /аІ®аІ§аіҚаІҜаІҫаІЁаіҚаІ№/i,
    morning: /аІ¬аіҶаІіаІ—аіҚаІ—аіҶ/i,
    afternoon: /аІ®аІ§аіҚаІҜаІҫаІЁаіҚаІ№/i,
    evening: /аІёаІӮаІңаіҶ/i,
    night: /аІ°аІҫаІӨаіҚаІ°аІҝ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
