export const formatDistance = (token, count, options) => {
  // Return word instead of `in one day` or `one day ago`
  if (token === "xDays" && options?.addSuffix && count <= 2) {
    if (options.comparison && options.comparison > 0) {
      return count === 1 ? "ЧһЧ—ЧЁ" : "ЧһЧ—ЧЁЧӘЧҷЧҷЧқ";
    }

    return count === 1 ? "ЧҗЧӘЧһЧ•Чң" : "Ч©ЧңЧ©Ч•Чқ";
  }

  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else if (count === 2) {
    result = tokenValue.two;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "Ч‘ЧўЧ•Ч“ " + result;
    } else {
      return "ЧңЧӨЧ Чҷ " + result;
    }
  }

  return result;
};
