import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";
import { localeToNumber } from "./localize.js";

const matchOrdinalNumberPattern = /^[аҘҰаҘ§аҘЁаҘ©аҘӘаҘ«аҘ¬аҘӯаҘ®аҘҜ]+/i;
const parseOrdinalNumberPattern = /^[аҘҰаҘ§аҘЁаҘ©аҘӘаҘ«аҘ¬аҘӯаҘ®аҘҜ]+/i;

const matchEraPatterns = {
  narrow: /^(аӨҲаӨёаӨҫ-аӨӘаҘӮаӨ°аҘҚаӨө|аӨҲаӨёаҘҚаӨөаҘҖ)/i,
  abbreviated: /^(аӨҲаӨёаӨҫ\.?\s?аӨӘаҘӮаӨ°аҘҚаӨө\.?|аӨҲаӨёаӨҫ\.?)/i,
  wide: /^(аӨҲаӨёаӨҫ-аӨӘаҘӮаӨ°аҘҚаӨө|аӨҲаӨёаӨөаҘҖ аӨӘаҘӮаӨ°аҘҚаӨө|аӨҲаӨёаӨөаҘҖ аӨёаӨЁ|аӨҲаӨёаӨөаҘҖ)/i,
};

const parseEraPatterns = {
  any: [/^b/i, /^(a|c)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^аӨӨаӨҝ[1234]/i,
  wide: /^[1234](аӨӘаӨ№аӨІаҘҖ|аӨҰаҘӮаӨёаӨ°аҘҖ|аӨӨаҘҖаӨёаӨ°аҘҖ|аӨҡаҘҢаӨҘаҘҖ)? аӨӨаӨҝаӨ®аӨҫаӨ№аҘҖ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  // eslint-disable-next-line no-misleading-character-class
  narrow: /^[аӨңаӨ«аӨјаӨ®аӨҫаӨ…аӨӘаҘҚаӨ®аӨҲаӨңаҘӮаӨЁаӨңаҘҒаӨ…аӨ—аӨёаӨҝаӨ…аӨ•аҘҚаӨӨаӨЁаӨҰаӨҝ]/i,
  abbreviated: /^(аӨңаӨЁ|аӨ«аӨјаӨ°|аӨ®аӨҫаӨ°аҘҚаӨҡ|аӨ…аӨӘаҘҚ|аӨ®аӨҲ|аӨңаҘӮаӨЁ|аӨңаҘҒаӨІ|аӨ…аӨ—|аӨёаӨҝаӨӨ|аӨ…аӨ•аҘҚаӨӨаҘӮ|аӨЁаӨө|аӨҰаӨҝаӨё)/i,
  wide: /^(аӨңаӨЁаӨөаӨ°аҘҖ|аӨ«аӨјаӨ°аӨөаӨ°аҘҖ|аӨ®аӨҫаӨ°аҘҚаӨҡ|аӨ…аӨӘаҘҚаӨ°аҘҲаӨІ|аӨ®аӨҲ|аӨңаҘӮаӨЁ|аӨңаҘҒаӨІаӨҫаӨҲ|аӨ…аӨ—аӨёаҘҚаӨӨ|аӨёаӨҝаӨӨаӨӮаӨ¬аӨ°|аӨ…аӨ•аҘҚаӨӨаҘӮаӨ¬аӨ°|аӨЁаӨөаӨӮаӨ¬аӨ°|аӨҰаӨҝаӨёаӨӮаӨ¬аӨ°)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^аӨң/i,
    /^аӨ«аӨј/i,
    /^аӨ®аӨҫ/i,
    /^аӨ…аӨӘаҘҚ/i,
    /^аӨ®аӨҲ/i,
    /^аӨңаҘӮ/i,
    /^аӨңаҘҒ/i,
    /^аӨ…аӨ—/i,
    /^аӨёаӨҝ/i,
    /^аӨ…аӨ•аҘҚаӨӨаҘӮ/i,
    /^аӨЁ/i,
    /^аӨҰаӨҝ/i,
  ],

  any: [
    /^аӨңаӨЁ/i,
    /^аӨ«аӨј/i,
    /^аӨ®аӨҫ/i,
    /^аӨ…аӨӘаҘҚ/i,
    /^аӨ®аӨҲ/i,
    /^аӨңаҘӮ/i,
    /^аӨңаҘҒ/i,
    /^аӨ…аӨ—/i,
    /^аӨёаӨҝ/i,
    /^аӨ…аӨ•аҘҚаӨӨаҘӮ/i,
    /^аӨЁаӨө/i,
    /^аӨҰаӨҝаӨё/i,
  ],
};

const matchDayPatterns = {
  // eslint-disable-next-line no-misleading-character-class
  narrow: /^[аӨ°аӨөаӨҝаӨёаҘӢаӨ®аӨ®аӨӮаӨ—аӨІаӨ¬аҘҒаӨ§аӨ—аҘҒаӨ°аҘҒаӨ¶аҘҒаӨ•аҘҚаӨ°аӨ¶аӨЁаӨҝ]/i,
  short: /^(аӨ°аӨөаӨҝ|аӨёаҘӢаӨ®|аӨ®аӨӮаӨ—аӨІ|аӨ¬аҘҒаӨ§|аӨ—аҘҒаӨ°аҘҒ|аӨ¶аҘҒаӨ•аҘҚаӨ°|аӨ¶аӨЁаӨҝ)/i,
  abbreviated: /^(аӨ°аӨөаӨҝ|аӨёаҘӢаӨ®|аӨ®аӨӮаӨ—аӨІ|аӨ¬аҘҒаӨ§|аӨ—аҘҒаӨ°аҘҒ|аӨ¶аҘҒаӨ•аҘҚаӨ°|аӨ¶аӨЁаӨҝ)/i,
  wide: /^(аӨ°аӨөаӨҝаӨөаӨҫаӨ°|аӨёаҘӢаӨ®аӨөаӨҫаӨ°|аӨ®аӨӮаӨ—аӨІаӨөаӨҫаӨ°|аӨ¬аҘҒаӨ§аӨөаӨҫаӨ°|аӨ—аҘҒаӨ°аҘҒаӨөаӨҫаӨ°|аӨ¶аҘҒаӨ•аҘҚаӨ°аӨөаӨҫаӨ°|аӨ¶аӨЁаӨҝаӨөаӨҫаӨ°)/i,
};
const parseDayPatterns = {
  narrow: [/^аӨ°аӨөаӨҝ/i, /^аӨёаҘӢаӨ®/i, /^аӨ®аӨӮаӨ—аӨІ/i, /^аӨ¬аҘҒаӨ§/i, /^аӨ—аҘҒаӨ°аҘҒ/i, /^аӨ¶аҘҒаӨ•аҘҚаӨ°/i, /^аӨ¶аӨЁаӨҝ/i],

  any: [/^аӨ°аӨөаӨҝ/i, /^аӨёаҘӢаӨ®/i, /^аӨ®аӨӮаӨ—аӨІ/i, /^аӨ¬аҘҒаӨ§/i, /^аӨ—аҘҒаӨ°аҘҒ/i, /^аӨ¶аҘҒаӨ•аҘҚаӨ°/i, /^аӨ¶аӨЁаӨҝ/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(аӨӘаҘӮ|аӨ…|аӨ®|аӨҰ.\?|аӨёаҘҒ|аӨҰаҘӢ|аӨ¶аӨҫ|аӨ°аӨҫ)/i,
  any: /^(аӨӘаҘӮаӨ°аҘҚаӨөаӨҫаӨ№аҘҚаӨЁ|аӨ…аӨӘаӨ°аӨҫаӨ№аҘҚаӨЁ|аӨ®|аӨҰ.\?|аӨёаҘҒ|аӨҰаҘӢ|аӨ¶аӨҫ|аӨ°аӨҫ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^аӨӘаҘӮаӨ°аҘҚаӨөаӨҫаӨ№аҘҚаӨЁ/i,
    pm: /^аӨ…аӨӘаӨ°аӨҫаӨ№аҘҚаӨЁ/i,
    midnight: /^аӨ®аӨ§аҘҚаӨҜ/i,
    noon: /^аӨҰаҘӢ/i,
    morning: /аӨёаҘҒ/i,
    afternoon: /аӨҰаҘӢ/i,
    evening: /аӨ¶аӨҫ/i,
    night: /аӨ°аӨҫ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: localeToNumber,
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
