import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(СҮРё)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(Рј\.Р°|Рј\.)/i,
  abbreviated: /^(Рј\.Р°|Рј\.)/i,
  wide: /^(РјРёР»РҫРҙРҙР°РҪ Р°РІРІР°Р»|РјРёР»РҫРҙРҙР°РҪ РәРөР№РёРҪ)/i,
};
const parseEraPatterns = {
  any: [/^Рј/i, /^Р°/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]-СҮРҫСҖ./i,
  wide: /^[1234]-СҮРҫСҖР°Рә/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[СҸС„РјР°РјРёРёР°СҒРҫРҪРҙ]/i,
  abbreviated: /^(СҸРҪРІ|С„РөРІ|РјР°СҖ|Р°РҝСҖ|РјР°Р№|РёСҺРҪ|РёСҺР»|Р°РІРі|СҒРөРҪ|РҫРәСӮ|РҪРҫСҸ|РҙРөРә)/i,
  wide: /^(СҸРҪРІР°СҖ|С„РөРІСҖР°Р»|РјР°СҖСӮ|Р°РҝСҖРөР»|РјР°Р№|РёСҺРҪ|РёСҺР»|Р°РІРіСғСҒСӮ|СҒРөРҪСӮР°РұСҖ|РҫРәСӮР°РұСҖ|РҪРҫСҸРұСҖ|РҙРөРәР°РұСҖ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^СҸ/i,
    /^С„/i,
    /^Рј/i,
    /^Р°/i,
    /^Рј/i,
    /^Рё/i,
    /^Рё/i,
    /^Р°/i,
    /^СҒ/i,
    /^Рҫ/i,
    /^РҪ/i,
    /^Рҙ/i,
  ],

  any: [
    /^СҸ/i,
    /^С„/i,
    /^РјР°СҖ/i,
    /^Р°Рҝ/i,
    /^РјР°Р№/i,
    /^РёСҺРҪ/i,
    /^РёСҺР»/i,
    /^Р°РІ/i,
    /^СҒ/i,
    /^Рҫ/i,
    /^РҪ/i,
    /^Рҙ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[СҸРҙСҒСҮРҝР¶СҲ]/i,
  short: /^(СҸРә|РҙСғ|СҒРө|СҮРҫ|РҝР°|Р¶Сғ|СҲР°)/i,
  abbreviated: /^(СҸРәСҲ|РҙСғСҲ|СҒРөСҲ|СҮРҫСҖ|РҝР°Р№|Р¶СғРј|СҲР°РҪ)/i,
  wide: /^(СҸРәСҲР°РҪРұР°|РҙСғСҲР°РҪРұР°|СҒРөСҲР°РҪРұР°|СҮРҫСҖСҲР°РҪРұР°|РҝР°Р№СҲР°РҪРұР°|Р¶СғРјР°|СҲР°РҪРұР°)/i,
};
const parseDayPatterns = {
  narrow: [/^СҸ/i, /^Рҙ/i, /^СҒ/i, /^СҮ/i, /^Рҝ/i, /^Р¶/i, /^СҲ/i],
  any: [/^СҸРә/i, /^РҙСғ/i, /^СҒРө/i, /^СҮРҫСҖ/i, /^РҝР°Р№/i, /^Р¶Сғ/i, /^СҲР°РҪ/i],
};

const matchDayPeriodPatterns = {
  any: /^(Рҝ\.Рҫ\.|Рҝ\.Рә\.|СҸСҖРёРј СӮСғРҪ|РҝРөСҲРёРҪРҙР°РҪ РәРөР№РёРҪ|(СҚСҖСӮР°Р»Р°Рұ|РҝРөСҲРёРҪРҙР°РҪ РәРөР№РёРҪ|РәРөСҮР°СҒРё|СӮСғРҪ))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^Рҝ\.Рҫ\./i,
    pm: /^Рҝ\.Рә\./i,
    midnight: /^СҸСҖРёРј СӮСғРҪ/i,
    noon: /^РҝРөСҲРёРҪРҙР°РҪ РәРөР№РёРҪ/i,
    morning: /СҚСҖСӮР°Р»Р°Рұ/i,
    afternoon: /РҝРөСҲРёРҪРҙР°РҪ РәРөР№РёРҪ/i,
    evening: /РәРөСҮР°СҒРё/i,
    night: /СӮСғРҪ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
