import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-бғҡбғҳ|-бғ”)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(бғ©бғ•?\.бғ¬)/i,
  abbreviated: /^(бғ©бғ•?\.бғ¬)/i,
  wide: /^(бғ©бғ•бғ”бғңбғЎ бғ¬бғ”бғҡбғ—бғҗбғҰбғ бғҳбғӘбғ®бғ•бғҗбғӣбғ“бғ”|бғҘбғ бғҳбғЎбғўбғ”бғЁбғқбғ‘бғҗбғӣбғ“бғ”|бғ©бғ•бғ”бғңбғҳ бғ¬бғ”бғҡбғ—бғҗбғҰбғ бғҳбғӘбғ®бғ•бғҳбғ—|бғҘбғ бғҳбғЎбғўбғ”бғЁбғқбғ‘бғҳбғ“бғҗбғң)/i,
};
const parseEraPatterns = {
  any: [
    /^(бғ©бғ•бғ”бғңбғЎ бғ¬бғ”бғҡбғ—бғҗбғҰбғ бғҳбғӘбғ®бғ•бғҗбғӣбғ“бғ”|бғҘбғ бғҳбғЎбғўбғ”бғЁбғқбғ‘бғҗбғӣбғ“бғ”)/i,
    /^(бғ©бғ•бғ”бғңбғҳ бғ¬бғ”бғҡбғ—бғҗбғҰбғ бғҳбғӘбғ®бғ•бғҳбғ—|бғҘбғ бғҳбғЎбғўбғ”бғЁбғқбғ‘бғҳбғ“бғҗбғң)/i,
  ],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]-(бғҡбғҳ|бғ”)? бғҷбғ•/i,
  wide: /^[1234]-(бғҡбғҳ|бғ”)? бғҷбғ•бғҗбғ бғўбғҗбғҡбғҳ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  any: /^(бғҳбғҗ|бғ—бғ”|бғӣбғҗ|бғҗбғһ|бғӣбғЎ|бғ•бғң|бғ•бғҡ|бғҗбғ’|бғЎбғ”|бғқбғҘ|бғңбғқ|бғ“бғ”)/i,
};
const parseMonthPatterns = {
  any: [
    /^бғҳбғҗ/i,
    /^бғ—/i,
    /^бғӣбғҗбғ /i,
    /^бғҗбғһ/i,
    /^бғӣбғҗбғҳ/i,
    /^бғҳ?бғ•бғң/i,
    /^бғҳ?бғ•бғҡ/i,
    /^бғҗбғ’/i,
    /^бғЎ/i,
    /^бғқ/i,
    /^бғң/i,
    /^бғ“/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(бғҷбғ•|бғқбғ |бғЎбғҗ|бғқбғ—|бғ®бғЈ|бғһбғҗ|бғЁбғҗ)/i,
  short: /^(бғҷбғ•бғҳ|бғқбғ бғЁ|бғЎбғҗбғӣ|бғқбғ—бғ®|бғ®бғЈбғ—|бғһбғҗбғ |бғЁбғҗбғ‘)/i,
  wide: /^(бғҷбғ•бғҳбғ бғҗ|бғқбғ бғЁбғҗбғ‘бғҗбғ—бғҳ|бғЎбғҗбғӣбғЁбғҗбғ‘бғҗбғ—бғҳ|бғқбғ—бғ®бғЁбғҗбғ‘бғҗбғ—бғҳ|бғ®бғЈбғ—бғЁбғҗбғ‘бғҗбғ—бғҳ|бғһбғҗбғ бғҗбғЎбғҷбғ”бғ•бғҳ|бғЁбғҗбғ‘бғҗбғ—бғҳ)/i,
};
const parseDayPatterns = {
  any: [/^бғҷбғ•/i, /^бғқбғ /i, /^бғЎбғҗ/i, /^бғқбғ—/i, /^бғ®бғЈ/i, /^бғһбғҗ/i, /^бғЁбғҗ/i],
};

const matchDayPeriodPatterns = {
  any: /^([ap]\.?\s?m\.?|бғЁбғЈбғҗбғҰ|бғ“бғҳбғҡ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^a/i,
    pm: /^p/i,
    midnight: /^бғЁбғЈбғҗбғҰ/i,
    noon: /^бғЁбғЈбғҗбғ“бғҰ/i,
    morning: /^бғ“бғҳбғҡ/i,
    afternoon: /бғңбғҗбғЁбғЈбғҗбғ“бғҰбғ”бғ•бғЎ/i,
    evening: /бғЎбғҗбғҰбғҗбғӣбғқ/i,
    night: /бғҰбғҗбғӣ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
