import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(th|st|nd|rd)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(ЩӮ|ШЁ)/i,
  abbreviated: /^(ЩӮ\.?\s?Щ…\.?|ЩӮ\.?\s?ШҜ\.?\s?Щ…\.?|Щ…\.?\s?|ШҜ\.?\s?Щ…\.?)/i,
  wide: /^(ЩӮШЁЩ„ Ш§ШІ Щ…ЫҢЩ„Ш§ШҜ|ЩӮШЁЩ„ Ш§ШІ ШҜЩҲШұШ§ЩҶ Щ…ШҙШӘШұЪ©|Щ…ЫҢЩ„Ш§ШҜЫҢ|ШҜЩҲШұШ§ЩҶ Щ…ШҙШӘШұЪ©|ШЁШ№ШҜ Ш§ШІ Щ…ЫҢЩ„Ш§ШҜ)/i,
};
const parseEraPatterns = {
  any: [/^ЩӮШЁЩ„/i, /^ШЁШ№ШҜ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^ШівҖҢЩ…[1234]/i,
  wide: /^ШіЩҮвҖҢЩ…Ш§ЩҮЩҮ [1234]/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[Ш¬ЪҳЩҒЩ…ШўШ§Щ…Ш§ШіЩҶШҜ]/i,
  abbreviated:
    /^(Ш¬ЩҶЩҲ|ЪҳШ§ЩҶЩҖ|ЪҳШ§ЩҶЩҲЫҢЩҮ|ЩҒЩҲШұЫҢЩҮ|ЩҒЩҲШұ|Щ…Ш§ШұШі|ШўЩҲШұЫҢЩ„|ШўЩҫШұ|Щ…ЩҮ|Щ…ЫҢ|ЪҳЩҲШҰЩҶ|Ш¬ЩҲЩҶ|Ш¬ЩҲЩ„|Ш¬ЩҲЩ„ЩҖ|ЪҳЩҲШҰЫҢЩҮ|Ш§ЩҲШӘ|ШўЪҜЩҲ|ШіЩҫШӘЩ…ШЁШұ|ШіЩҫШӘШ§Щ…ШЁШұ|Ш§Ъ©ШӘШЁШұ|Ш§Ъ©ШӘЩҲШЁШұ|ЩҶЩҲШ§Щ…ШЁШұ|ЩҶЩҲШ§Щ…ЩҖ|ШҜШіШ§Щ…ШЁШұ|ШҜШіШ§Щ…ЩҖ|ШҜШіЩ…)/i,
  wide: /^(ЪҳШ§ЩҶЩҲЫҢЩҮ|Ш¬ЩҶЩҲШұЫҢ|ЩҒШЁШұЩҲШұЫҢ|ЩҒЩҲШұЫҢЩҮ|Щ…Ш§ШұЪҶ|Щ…Ш§ШұШі|ШўЩҫШұЫҢЩ„|Ш§ЩҫШұЫҢЩ„|Ш§ЫҢЩҫШұЫҢЩ„|ШўЩҲШұЫҢЩ„|Щ…ЩҮ|Щ…ЫҢ|ЪҳЩҲШҰЩҶ|Ш¬ЩҲЩҶ|Ш¬ЩҲЩ„Ш§ЫҢ|ЪҳЩҲШҰЫҢЩҮ|ШўЪҜШіШӘ|Ш§ЪҜШіШӘ|ШўЪҜЩҲШіШӘ|Ш§ЩҲШӘ|ШіЩҫШӘЩ…ШЁШұ|ШіЩҫШӘШ§Щ…ШЁШұ|Ш§Ъ©ШӘШЁШұ|Ш§Ъ©ШӘЩҲШЁШұ|ЩҶЩҲШ§Щ…ШЁШұ|ЩҶЩҲЩ…ШЁШұ|ШҜШіШ§Щ…ШЁШұ|ШҜШіЩ…ШЁШұ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^(Ъҳ|Ш¬)/i,
    /^ЩҒ/i,
    /^Щ…/i,
    /^(Шў|Ш§)/i,
    /^Щ…/i,
    /^(Ъҳ|Ш¬)/i,
    /^(Ш¬|Ъҳ)/i,
    /^(Шў|Ш§)/i,
    /^Ші/i,
    /^Ш§/i,
    /^ЩҶ/i,
    /^ШҜ/i,
  ],

  any: [
    /^ЪҳШ§/i,
    /^ЩҒ/i,
    /^Щ…Ш§/i,
    /^ШўЩҫ/i,
    /^(Щ…ЫҢ|Щ…ЩҮ)/i,
    /^(ЪҳЩҲШҰЩҶ|Ш¬ЩҲЩҶ)/i,
    /^(ЪҳЩҲШҰЫҢ|Ш¬ЩҲЩ„)/i,
    /^(Ш§ЩҲШӘ|ШўЪҜ)/i,
    /^Ші/i,
    /^(Ш§ЩҲЪ©|Ш§Ъ©)/i,
    /^ЩҶ/i,
    /^ШҜ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ШҙЫҢШҜШіЪҶЩҫШ¬]/i,
  short: /^(Шҙ|Ш¬|1Шҙ|2Шҙ|3Шҙ|4Шҙ|5Шҙ)/i,
  abbreviated: /^(ЫҢЪ©ШҙЩҶШЁЩҮ|ШҜЩҲШҙЩҶШЁЩҮ|ШіЩҮвҖҢШҙЩҶШЁЩҮ|ЪҶЩҮШ§ШұШҙЩҶШЁЩҮ|ЩҫЩҶШ¬вҖҢШҙЩҶШЁЩҮ|Ш¬Щ…Ш№ЩҮ|ШҙЩҶШЁЩҮ)/i,
  wide: /^(ЫҢЪ©ШҙЩҶШЁЩҮ|ШҜЩҲШҙЩҶШЁЩҮ|ШіЩҮвҖҢШҙЩҶШЁЩҮ|ЪҶЩҮШ§ШұШҙЩҶШЁЩҮ|ЩҫЩҶШ¬вҖҢШҙЩҶШЁЩҮ|Ш¬Щ…Ш№ЩҮ|ШҙЩҶШЁЩҮ)/i,
};
const parseDayPatterns = {
  narrow: [/^ЫҢ/i, /^ШҜЩҲ/i, /^Ші/i, /^ЪҶ/i, /^Щҫ/i, /^Ш¬/i, /^Шҙ/i],
  any: [
    /^(ЫҢ|1Шҙ|ЫҢЪ©ШҙЩҶШЁЩҮ)/i,
    /^(ШҜ|2Шҙ|ШҜЩҲШҙЩҶШЁЩҮ)/i,
    /^(Ші|3Шҙ|ШіЩҮвҖҢШҙЩҶШЁЩҮ)/i,
    /^(ЪҶ|4Шҙ|ЪҶЩҮШ§ШұШҙЩҶШЁЩҮ)/i,
    /^(Щҫ|5Шҙ|ЩҫЩҶШ¬ШҙЩҶШЁЩҮ)/i,
    /^(Ш¬|Ш¬Щ…Ш№ЩҮ)/i,
    /^(Шҙ|ШҙЩҶШЁЩҮ)/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow: /^(ШЁ|ЩӮ|ЩҶ|Шё|Шө|ШЁ.Шё.|Ш№|Шҙ)/i,
  abbreviated: /^(ЩӮ.Шё.|ШЁ.Шё.|ЩҶЫҢЩ…ЩҮвҖҢШҙШЁ|ШёЩҮШұ|ШөШЁШӯ|ШЁШ№ШҜШ§ШІШёЩҮШұ|Ш№ШөШұ|ШҙШЁ)/i,
  wide: /^(ЩӮШЁЩ„вҖҢШ§ШІШёЩҮШұ|ЩҶЫҢЩ…ЩҮвҖҢШҙШЁ|ШёЩҮШұ|ШөШЁШӯ|ШЁШ№ШҜШ§ШІШёЩҮШұ|Ш№ШөШұ|ШҙШЁ)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^(ЩӮ|ЩӮ.Шё.|ЩӮШЁЩ„вҖҢШ§ШІШёЩҮШұ)/i,
    pm: /^(ШЁ|ШЁ.Шё.|ШЁШ№ШҜШ§ШІШёЩҮШұ)/i,
    midnight: /^(вҖҢЩҶЫҢЩ…ЩҮвҖҢШҙШЁ|ЩҶ)/i,
    noon: /^(Шё|ШёЩҮШұ)/i,
    morning: /(Шө|ШөШЁШӯ)/i,
    afternoon: /(ШЁ|ШЁ.Шё.|ШЁШ№ШҜШ§ШІШёЩҮШұ)/i,
    evening: /(Ш№|Ш№ШөШұ)/i,
    night: /(Шҙ|ШҙШЁ)/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
