const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "dЖ°б»ӣi 1 giГўy",
    other: "dЖ°б»ӣi {{count}} giГўy",
  },

  xSeconds: {
    one: "1 giГўy",
    other: "{{count}} giГўy",
  },

  halfAMinute: "nб»ӯa phГәt",

  lessThanXMinutes: {
    one: "dЖ°б»ӣi 1 phГәt",
    other: "dЖ°б»ӣi {{count}} phГәt",
  },

  xMinutes: {
    one: "1 phГәt",
    other: "{{count}} phГәt",
  },

  aboutXHours: {
    one: "khoбәЈng 1 giб»қ",
    other: "khoбәЈng {{count}} giб»қ",
  },

  xHours: {
    one: "1 giб»қ",
    other: "{{count}} giб»қ",
  },

  xDays: {
    one: "1 ngГ y",
    other: "{{count}} ngГ y",
  },

  aboutXWeeks: {
    one: "khoбәЈng 1 tuбә§n",
    other: "khoбәЈng {{count}} tuбә§n",
  },

  xWeeks: {
    one: "1 tuбә§n",
    other: "{{count}} tuбә§n",
  },

  aboutXMonths: {
    one: "khoбәЈng 1 thГЎng",
    other: "khoбәЈng {{count}} thГЎng",
  },

  xMonths: {
    one: "1 thГЎng",
    other: "{{count}} thГЎng",
  },

  aboutXYears: {
    one: "khoбәЈng 1 nДғm",
    other: "khoбәЈng {{count}} nДғm",
  },

  xYears: {
    one: "1 nДғm",
    other: "{{count}} nДғm",
  },

  overXYears: {
    one: "hЖЎn 1 nДғm",
    other: "hЖЎn {{count}} nДғm",
  },

  almostXYears: {
    one: "gбә§n 1 nДғm",
    other: "gбә§n {{count}} nДғm",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + " nб»Ҝa";
    } else {
      return result + " trЖ°б»ӣc";
    }
  }

  return result;
};
