import { isSameWeek } from "../../../isSameWeek.js";

const accusativeWeekdays = [
  "РІРҫСҒРәСҖРөСҒРөРҪСҢРө",
  "РҝРҫРҪРөРҙРөР»СҢРҪРёРә",
  "РІСӮРҫСҖРҪРёРә",
  "СҒСҖРөРҙСғ",
  "СҮРөСӮРІРөСҖРі",
  "РҝСҸСӮРҪРёСҶСғ",
  "СҒСғРұРұРҫСӮСғ",
];

function lastWeek(day) {
  const weekday = accusativeWeekdays[day];

  switch (day) {
    case 0:
      return "'РІ РҝСҖРҫСҲР»РҫРө " + weekday + " РІ' p";
    case 1:
    case 2:
    case 4:
      return "'РІ РҝСҖРҫСҲР»СӢР№ " + weekday + " РІ' p";
    case 3:
    case 5:
    case 6:
      return "'РІ РҝСҖРҫСҲР»СғСҺ " + weekday + " РІ' p";
  }
}

function thisWeek(day) {
  const weekday = accusativeWeekdays[day];

  if (day === 2 /* Tue */) {
    return "'РІРҫ " + weekday + " РІ' p";
  } else {
    return "'РІ " + weekday + " РІ' p";
  }
}

function nextWeek(day) {
  const weekday = accusativeWeekdays[day];

  switch (day) {
    case 0:
      return "'РІ СҒР»РөРҙСғСҺСүРөРө " + weekday + " РІ' p";
    case 1:
    case 2:
    case 4:
      return "'РІ СҒР»РөРҙСғСҺСүРёР№ " + weekday + " РІ' p";
    case 3:
    case 5:
    case 6:
      return "'РІ СҒР»РөРҙСғСҺСүСғСҺ " + weekday + " РІ' p";
  }
}

const formatRelativeLocale = {
  lastWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return lastWeek(day);
    }
  },
  yesterday: "'РІСҮРөСҖР° РІ' p",
  today: "'СҒРөРіРҫРҙРҪСҸ РІ' p",
  tomorrow: "'Р·Р°РІСӮСҖР° РІ' p",
  nextWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return nextWeek(day);
    }
  },
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
