const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const unit = String(options?.unit);

  switch (unit) {
    case "year":
      return `${number}гҒӯгӮ“`;
    case "quarter":
      return `гҒ гҒ„${number}гҒ—гҒҜгӮ“гҒҚ`;
    case "month":
      return `${number}гҒҢгҒӨ`;
    case "week":
      return `гҒ гҒ„${number}гҒ—гӮ…гҒҶ`;
    case "date":
      return `${number}гҒ«гҒЎ`;
    case "hour":
      return `${number}гҒҳ`;
    case "minute":
      return `${number}гҒөгӮ“`;
    case "second":
      return `${number}гҒігӮҮгҒҶ`;
    default:
      return `${number}`;
  }
};

export const localize = {
  ordinalNumber: ordinalNumber,

  era: buildLocalizeFn({
    values: eraValues,
    defaultWidth: "wide",
  }),

  quarter: buildLocalizeFn({
    values: quarterValues,
    defaultWidth: "wide",
    argumentCallback: (quarter) => Number(quarter) - 1,
  }),

  month: buildLocalizeFn({
    values: monthValues,
    defaultWidth: "wide",
  }),

  day: buildLocalizeFn({
    values: dayValues,
    defaultWidth: "wide",
  }),

  dayPeriod: buildLocalizeFn({
    values: dayPeriodValues,
    defaultWidth: "wide",
    formattingValues: formattingDayPeriodValues,
    defaultFormattingWidth: "wide",
  }),
};
