const formatRelativeLocale = {
  lastWeek: "'СһСӮРіР°РҪ' eeee p 'РҙР°'",
  yesterday: "'РәРөСҮР°' p 'РҙР°'",
  today: "'РұСғРіСғРҪ' p 'РҙР°'",
  tomorrow: "'СҚСҖСӮР°РіР°' p 'РҙР°'",
  nextWeek: "eeee p 'РҙР°'",
  other: "P",
};

export const formatRelative = (token, _date, _baseDate, _options) =>
  formatRelativeLocale[token];
