const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const unit = options?.unit;

  if (unit === "quarter") {
    // many news outlets use "quГҪ I"...
    switch (number) {
      case 1:
        return "I";
      case 2:
        return "II";
      case 3:
        return "III";
      case 4:
        return "IV";
    }
  } else if (unit === "day") {
    // day of week in Vietnamese has ordinal number meaning,
    // so we should use them, else it'll sound weird
    switch (number) {
      case 1:
        return "thб»© 2"; // meaning 2nd day but it's the first day of the week :D
      case 2:
        return "thб»© 3"; // meaning 3rd day
      case 3:
        return "thб»© 4"; // meaning 4th day and so on
      case 4:
        return "thб»© 5";
      case 5:
        return "thб»© 6";
      case 6:
        return "thб»© 7";
      case 7:
        return "chб»§ nhбәӯt"; // meaning Sunday, there's no 8th day :D
    }
  } else if (unit === "week") {
    if (number === 1) {
      return "thб»© nhбәҘt";
    } else {
      return "thб»© " + number;
    }
  } else if (unit === "dayOfYear") {
    if (number === 1) {
      return "Д‘бә§u tiГӘn";
    } else {
      return "thб»© " + number;
    }
  }

  // there are no different forms of ordinal numbers in Vietnamese
  return String(number);
};

